// Unit 17: Karneval im Rheinland
// Level: B1

const UNIT_17 =
{n:17,lang:"de",srcLang:"en",track:"v2",title:"Karneval im Rheinland",sub:"Cologne carnival, infinitive clauses, costumes, Rosenmontagszug",icon:"\uD83C\uDFAD",level:"B1.2",color:"#7B5EE8",lessons:[

// ─── Lesson 1: Kölle Alaaf! ───────────────────────────────────
{id:"deu_r17l1",title:"K\u00f6lle Alaaf!",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"K\u00f6lle Alaaf!",desc:"Verumius steps off the ICE in Cologne. The cathedral towers over the chaos. Everyone is in costume. Confetti on the ground. Music everywhere. Welcome to Karneval.",goals:["Learn key Karneval vocabulary","Experience Germany's wildest tradition through Verumius's eyes","Discover why Cologne goes crazy during Karneval"]},
{type:"teach",trg:"der Karneval",src:"the carnival",pos:"noun",gender:"m",note:"Masculine noun. The wild celebration before Lent.\nIn the Rhineland, Karneval season starts on 11.11. at 11:11.",example:"A: Wann beginnt der Karneval?\nB: Offiziell am 11. November um 11:11 Uhr.\nA: Und wann ist der H\u00f6hepunkt?\nB: Am Rosenmontag, im Februar oder M\u00e4rz.",exampleSrc:"A: When does carnival begin?\nB: Officially on November 11th at 11:11.\nA: And when is the highlight?\nB: On Rose Monday, in February or March.",funFact:"From Latin 'carne vale' (farewell to meat). The number 11 is the 'fool's number' because it stands one above the holy 10. Over 1.5 million people flood Cologne's streets on Rosenmontag."},
{type:"teach",trg:"das Kost\u00fcm",src:"the costume",pos:"noun",gender:"n",note:"Neuter noun. During Karneval, wearing a Kost\u00fcm is not optional.\nNot dressing up marks you as an outsider.",example:"A: Was f\u00fcr ein Kost\u00fcm tr\u00e4gst du?\nB: Ich bin eine Biene! Und du?\nA: Ich bin ein r\u00f6mischer Senator.\nB: Das passt perfekt zu dir!",exampleSrc:"A: What kind of costume are you wearing?\nB: I'm a bee! And you?\nA: I'm a Roman senator.\nB: That suits you perfectly!",funFact:"From French 'costume.' Up to 1.5 million costumed people flood Cologne's streets on Rosenmontag. Not dressing up marks you as an outsider instantly."},
{type:"teach",trg:"die Tradition",src:"the tradition",pos:"noun",gender:"f",note:"Feminine noun. Same as English, from Latin 'traditio' (handing down).\nRhineland Karneval traditions date back over 600 years.",example:"A: Ist Karneval eine alte Tradition?\nB: Ja, \u00fcber 600 Jahre alt im Rheinland.\nA: Jede Stadt hat eigene Traditionen?\nB: Genau. K\u00f6ln ruft 'Alaaf!', D\u00fcsseldorf ruft 'Helau!'",exampleSrc:"A: Is carnival an old tradition?\nB: Yes, over 600 years old in the Rhineland.\nA: Every city has its own traditions?\nB: Exactly. Cologne shouts 'Alaaf!', Düsseldorf shouts 'Helau!'",funFact:"Every city has its own greeting: 'Alaaf!' in Cologne, 'Helau!' in D\u00fcsseldorf. Using the wrong one in the wrong city is a social crime."},
{type:"teach",trg:"die Freude",src:"the joy",pos:"noun",gender:"f",note:"Feminine noun. From Old High German 'frewida.'\n'Freude sch\u00f6ner G\u00f6tterfunken' is the European anthem.",example:"A: Sp\u00fcrst du die Freude in der Luft?\nB: Ja! Alle Menschen lachen und tanzen.\nA: Das ist die Freude des Karnevals.\nB: So etwas habe ich noch nie erlebt.",exampleSrc:"A: Do you feel the joy in the air?\nB: Yes! Everyone is laughing and dancing.\nA: That is the joy of carnival.\nB: I've never experienced anything like this.",funFact:"Beethoven set Schiller's 'Ode an die Freude' to music. It became the European anthem. Joy is literally Europe's official emotion."},
{type:"teach",trg:"der Humor",src:"the humor",pos:"noun",gender:"m",note:"Masculine noun. Same in English and German, from Latin.\nGerman humor exists, despite the stereotype.",example:"A: Haben Deutsche wirklich keinen Humor?\nB: Quatsch! Karneval beweist das Gegenteil.\nA: Die politische Satire ist wirklich gut.\nB: Ja, deutscher Humor ist clever und mutig.",exampleSrc:"A: Do Germans really have no humor?\nB: Nonsense! Carnival proves the opposite.\nA: The political satire is really good.\nB: Yes, German humor is clever and bold.",funFact:"Karneval proves German humor exists. Political satire on parade floats is biting, clever, and fearless. Carnival comedians are celebrities."},
{type:"match",pairs:[{trg:"das Kost\u00fcm",src:"the costume"},{trg:"die Tradition",src:"the tradition"},{trg:"die Freude",src:"the joy"},{trg:"der Humor",src:"the humor"}]},
{type:"teach",trg:"der Hut",src:"the hat",pos:"noun",gender:"m",note:"Masculine noun. Same root as English 'hood.'\n'Hut ab!' (Hat off!) means 'Respect!'",example:"A: Sch\u00f6ner Hut! Woher hast du den?\nB: Selbst gemacht! Mit Federn und Glitzer.\nA: Hut ab! Der ist wirklich kreativ.\nB: Danke! Drei Abende Arbeit.",exampleSrc:"A: Nice hat! Where did you get it?\nB: Handmade! With feathers and glitter.\nA: Respect! It's really creative.\nB: Thanks! Three evenings of work.",funFact:"'Hut ab!' (Hat off!) means 'Respect!' Karneval hats range from tiny pointed Narrenkappen to enormous feathered creations."},
{type:"teach",trg:"der Schmuck",src:"the jewelry, the decoration",pos:"noun",gender:"m",note:"Masculine noun. From 'schm\u00fccken' (to decorate).\nEnglish borrowed 'schmuck' as an insult from Yiddish, but in German it means something beautiful.",example:"A: Du tr\u00e4gst so viel Schmuck heute!\nB: Beim Karneval gilt: je mehr, desto besser.\nA: Die Ketten und Ohrringe sind toll.\nB: Alles nur Modeschmuck, aber es gl\u00e4nzt!",exampleSrc:"A: You're wearing so much jewelry today!\nB: At carnival the rule is: the more, the better.\nA: The necklaces and earrings are great.\nB: All just costume jewelry, but it sparkles!",funFact:"In German, Schmuck means something beautiful. English borrowed 'schmuck' as an insult from Yiddish, a completely different meaning. During Karneval, the more Schmuck the better."},
{type:"mc",q:"Verumius sieht \u00fcberall Konfetti und bunte Kleider. Was ist das f\u00fcr ein Fest?",opts:["der Karneval","der Humor","die Tradition","die Freude"],ans:"der Karneval",hint:"The wild celebration before Lent, famous in Cologne, starting on 11.11. at 11:11."},
{type:"fb",s:"Verumius tr\u00e4gt keinen {1}. Er hat nur eine Toga.",a:["Hut"],opts:["Hut","Schmuck","Karneval","Humor"],hint:"Which accessory worn on the head is linked to the expression meaning 'respect!'?",sSrc:"Verumius is not wearing a hat. He only has a toga."},
{type:"teach",trg:"fr\u00f6hlich",src:"happy, cheerful",pos:"adj",gender:null,note:"From 'froh' (glad) + '-lich.' Describes bubbly, outward happiness.\nThe Rhineland is stereotyped as Germany's fr\u00f6hlich region.",example:"A: Warum sind alle so fr\u00f6hlich?\nB: Das ist der Geist des Karnevals!\nA: Sogar die Polizisten lachen.\nB: Fr\u00f6hliche Menschen \u00fcberall!",exampleSrc:"A: Why is everyone so cheerful?\nB: That's the spirit of carnival!\nA: Even the police officers are laughing.\nB: Happy people everywhere!",funFact:"'Fr\u00f6hliche Weihnachten!' means Merry Christmas. The Rhineland is stereotyped as Germany's most fr\u00f6hlich region."},
{type:"teach",trg:"verr\u00fcckt",src:"crazy",pos:"adj",gender:null,note:"Literally 'moved/shifted' (ver- + r\u00fccken).\nSomething shifted out of its normal place.",example:"A: Das ist ja verr\u00fcckt hier!\nB: Ja, Karneval ist offiziell verr\u00fcckt.\nA: Ein Mann im Bananenkost\u00fcm tanzt auf dem Tisch.\nB: Ganz normal beim Karneval!",exampleSrc:"A: This is crazy here!\nB: Yes, carnival is officially crazy.\nA: A man in a banana costume is dancing on the table.\nB: Totally normal at carnival!",funFact:"Literally means 'shifted out of place.' 'Das ist verr\u00fcckt!' is the German 'That's crazy!' Karneval is officially sanctioned verr\u00fcckt."},
{type:"teach",trg:"wundersch\u00f6n",src:"wonderfully beautiful",pos:"adj",gender:null,note:"Wunder (wonder) + sch\u00f6n (beautiful). A superlative that stacks wonder on top of beauty.\nStronger than just 'sch\u00f6n.'",example:"A: Schau mal die Kost\u00fcme!\nB: Wundersch\u00f6n! Besonders die Kleider.\nA: Die Farben sind unglaublich.\nB: K\u00f6ln ist heute wundersch\u00f6n.",exampleSrc:"A: Look at the costumes!\nB: Wonderfully beautiful! Especially the dresses.\nA: The colors are incredible.\nB: Cologne is wonderfully beautiful today.",funFact:"Germans use wundersch\u00f6n for landscapes, moments, and people they genuinely admire. It stacks wonder on top of beauty."},
{type:"teach",trg:"begeistert",src:"enthusiastic, thrilled",pos:"adj",gender:null,note:"From 'Geist' (spirit). Be-geist-ert = 'filled with spirit.'\nWhen you are begeistert, a spirit has entered you.",example:"A: Wie findest du den Karneval?\nB: Ich bin total begeistert!\nA: Das freut mich. Du strahlst richtig.\nB: So viel Energie und Freude!",exampleSrc:"A: How do you find the carnival?\nB: I'm totally thrilled!\nA: I'm glad. You're really glowing.\nB: So much energy and joy!",funFact:"From 'Geist' (spirit). When you are begeistert, a spirit has literally entered you. The perfect word for carnival energy."},
{type:"fb",s:"Ein Mann im Bananenkost\u00fcm tanzt auf dem Tisch. Das ist ja {1}!",a:["verr\u00fcckt"],opts:["verr\u00fcckt","fr\u00f6hlich","wundersch\u00f6n","kreativ"],hint:"Literally 'shifted out of place.' Which adjective means crazy?",sSrc:"A man in a banana costume dances on the table. That is crazy!"}
]},
{id:"deu_r17l1b",title:"K\u00f6lle Alaaf! (Teil 2)",icon:"\uD83C\uDF89",xp:15,board:true,steps:[
{type:"intro",title:"K\u00f6lle Alaaf! (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"mc",q:"Alle Menschen lachen und tanzen. Die Stimmung ist...",opts:["ernst und k\u00fchl","still und leise","fr\u00f6hlich","riesig und laut"],ans:"fr\u00f6hlich",hint:"From 'froh' (glad). Which adjective describes bubbly, outward happiness?"},
{type:"teach",trg:"riesig",src:"huge, enormous",pos:"adj",gender:null,note:"From 'Riese' (giant). Literally 'giant-like.'\nCologne's parade stretches over 7 kilometers.",example:"A: Die Wagen sind riesig!\nB: Manche sind \u00fcber zehn Meter hoch.\nA: Und die Menschenmenge ist auch riesig.\nB: \u00dcber eine Million Menschen!",exampleSrc:"A: The floats are enormous!\nB: Some are over ten meters tall.\nA: And the crowd is also huge.\nB: Over one million people!",funFact:"From 'Riese' (giant). Carnival floats are riesig. Cologne's parade stretches over 7 kilometers. Everything at Karneval is riesig."},
{type:"teach",trg:"kreativ",src:"creative",pos:"adj",gender:null,note:"From Latin 'creare.' Same in many languages.\nKarneval costumes reward kreative Ideen.",example:"A: Dein Kost\u00fcm ist sehr kreativ!\nB: Danke, ich habe es selbst gemacht.\nA: Aus was ist das?\nB: Aus Pappe, Farbe und Fantasie!",exampleSrc:"A: Your costume is very creative!\nB: Thanks, I made it myself.\nA: What is it made of?\nB: Cardboard, paint, and imagination!",funFact:"The best Karneval costumes are handmade, political, or absurdly original. A bed frame as a costume? Kreativ."},
{type:"teach",trg:"gr\u00fc\u00dfen",src:"to greet",pos:"verb",gender:null,note:"From 'Gru\u00df' (greeting). During Karneval, strangers gr\u00fc\u00dfen each other.\n'Alaaf!' and 'Helau!' replace 'Hallo.'",example:"A: Gr\u00fc\u00df dich! K\u00f6lle Alaaf!\nB: Alaaf! Sch\u00f6nes Kost\u00fcm!\nA: Danke! Beim Karneval gr\u00fc\u00dft man jeden.\nB: Das ist so anders als im Alltag.",exampleSrc:"A: Greetings! K\u00f6lle Alaaf!\nB: Alaaf! Nice costume!\nA: Thanks! At carnival you greet everyone.\nB: That's so different from everyday life.",funFact:"Greeting strangers in normal German life would be unusual. At Karneval it is mandatory. 'Alaaf!' and 'Helau!' replace 'Hallo.'"},
{type:"teach",trg:"schauen",src:"to look, to watch",pos:"verb",gender:null,note:"Southern German and Austrian for 'gucken.'\n'Schau mal!' (Look!) is what Mia says every five seconds.",example:"A: Schau mal, der Wagen!\nB: Wow, der ist riesig!\nA: Schau dir die Details an!\nB: Unglaublich. Ich kann nicht aufh\u00f6ren zu schauen.",exampleSrc:"A: Look, the float!\nB: Wow, it's enormous!\nA: Look at the details!\nB: Unbelievable. I can't stop looking.",funFact:"Standard German, slightly more literary than gucken. 'Schau mal!' (Look!) is the southern version of 'Guck mal!'"},
{type:"mc",q:"Verumius sieht die Kost\u00fcme und kann nicht aufh\u00f6ren zu schauen. Er ist...",opts:["begeistert","riesig","kreativ","verr\u00fcckt"],ans:"begeistert",hint:"From 'Geist' (spirit): filled with enthusiasm. Which adjective means thrilled?"},
{type:"fb",s:"Die Kost\u00fcme sind {1}! Jedes Detail ist anders.",a:["wundersch\u00f6n"],opts:["wundersch\u00f6n","riesig","kreativ","fr\u00f6hlich"],hint:"A compound adjective combining a word for miracle with beauty. The costumes are not just pretty, they are this.",sSrc:"The costumes are wonderfully beautiful! Every detail is different."},
{type:"teach",trg:"gucken",src:"to look, to peek",pos:"verb",gender:null,note:"Northern German and colloquial.\n'Guck mal!' = 'Look!' Same meaning as schauen but more casual.",example:"A: Guck mal, ein Pirat!\nB: Und da, eine Prinzessin!\nA: Man kann \u00fcberall hingucken.\nB: Jede Richtung ist Karneval.",exampleSrc:"A: Look, a pirate!\nB: And there, a princess!\nA: You can look everywhere.\nB: Every direction is carnival.",funFact:"Northern German and colloquial. Perfect pair with schauen: there is a LOT to guck at during Karneval."},
{type:"teach",trg:"winken",src:"to wave",pos:"verb",gender:null,note:"People wave at parade floats to get candy thrown to them.\n'Winke winke!' is baby talk for waving goodbye.",example:"A: Wink mal! Dann werfen sie Bonbons!\nB: So? (winkt enthusiastisch)\nA: Ja! Lauter! Kamelle!\nB: Es funktioniert! Ich habe Schokolade gefangen!",exampleSrc:"A: Wave! Then they'll throw candy!\nB: Like this? (waves enthusiastically)\nA: Yes! Louder! Kamelle!\nB: It works! I caught chocolate!",funFact:"At the Rosenmontagszug, enthusiastic winken equals more candy. 'Winke winke!' is baby talk for waving goodbye."},
{type:"teach",trg:"diesmal",src:"this time",pos:"adv",gender:null,note:"Dies (this) + mal (time/instance).\n'Diesmal ist alles anders' (This time everything is different).",example:"A: Warst du schon mal in K\u00f6ln?\nB: Ja, aber diesmal ist es anders.\nA: Warum?\nB: Diesmal bin ich beim Karneval!",exampleSrc:"A: Have you been to Cologne before?\nB: Yes, but this time it's different.\nA: Why?\nB: This time I'm at Carnival!",funFact:"Verumius has seen formal Germany, bureaucratic Germany, quiet Germany. Diesmal: wild Germany."},
{type:"mc",q:"Verumius sieht Menschen in bunten Kleidern. Was tragen sie?",opts:["bunte H\u00fcte","Kost\u00fcme","langer Schmuck","alte Formulare"],ans:"Kost\u00fcme",hint:"The special clothing people wear to transform into someone else during carnival."},
{type:"mc",q:"Mia ruft: 'K\u00f6lle Alaaf!' Was bedeutet das?",opts:["Eine h\u00f6fliche Bitte an alle um etwas Ruhe","Eine pers\u00f6nliche Beleidigung gegen jemanden","Ein k\u00f6lnischer Karnevalsgru\u00df","Ein sehr freundlicher pers\u00f6nlicher Abschied"],ans:"Ein k\u00f6lnischer Karnevalsgru\u00df",hint:"The traditional shout of celebration specific to Cologne's carnival."},
{type:"mc",q:"Was bedeutet 'gucken'?",opts:["this time","to look, to peek","huge, enormous","the jewelry, the decoration"],ans:"to look, to peek",hint:"A colloquial North German verb for using your eyes. 'Mal guck!' = 'Just check!'"},
{type:"fb",s:"Wie sagt man 'to wave' auf Deutsch? {1}",a:["winken"],opts:["riesig","die Tradition","winken","der Hut"],hint:"A hand gesture to say hello or goodbye. English cognate: 'wink' (related motion).",sSrc:"How do you say 'to wave' in German?"},
{type:"mc",q:"Was bedeutet 'diesmal'?",opts:["enthusiastic, thrilled","the tradition","this time","huge, enormous"],ans:"this time",hint:"Dies- (this) + Mal (occasion). Refers to the current instance, in contrast to previous occasions."},
{type:"fb",s:"Er hat mich freundlich {1}. Guten Tag, Herr Verumius!",a:"gegrüßt",opts:["gegrüßt","gewinkt","geguckt","gerufen"],hint:"The past participle of a verb meaning to greet someone politely.",sSrc:"He greeted me in a friendly way. Good day, Mr. Verumius!"}
]},

// ─── Lesson 2: Masken und Melodien ────────────────────────────
{id:"deu_r17l2",title:"Masken und Melodien",icon:"\uD83C\uDFB6",xp:15,board:true,steps:[
{type:"intro",title:"Masken und Melodien",desc:"Music, stages, performances. Karneval is not just costumes but also entertainment. Learn words for music, performance, and showbusiness.",goals:["Learn words for stage, music, and entertainment","Understand the -er/-erin pattern for profession names","Describe Karneval shows and street performers"]},
{type:"teach",trg:"die B\u00fchne",src:"the stage",pos:"noun",gender:"f",note:"Feminine noun. From Middle High German 'b\u00fchne' (raised platform).\nEvery Karneval has a B\u00fchne f\u00fcr die 'Sitzung' (formal comedy session).",example:"A: Wann ist der Auftritt auf der B\u00fchne?\nB: In zehn Minuten. Die Band macht sich bereit.\nA: Ich sehe die B\u00fchne von hier.\nB: Lass uns n\u00e4her gehen!",exampleSrc:"A: When is the performance on stage?\nB: In ten minutes. The band is getting ready.\nA: I can see the stage from here.\nB: Let's go closer!",funFact:"Every Karneval celebration has a B\u00fchne for the 'Sitzung' (formal comedy session). These are not amateur nights. Rhineland B\u00fchnenkultur is professional entertainment."},
{type:"teach",trg:"der Tanz",src:"the dance",pos:"noun",gender:"m",note:"Masculine noun. From Old French 'danse.'\nCarnival dances include the Funkenmariechen (female solo dancer).",example:"A: Magst du den Tanz?\nB: Ja, die T\u00e4nzerin ist fantastisch!\nA: Der Tanz ist eine Tradition.\nB: So elegant und gleichzeitig lustig.",exampleSrc:"A: Do you like the dance?\nB: Yes, the dancer is fantastic!\nA: The dance is a tradition.\nB: So elegant and funny at the same time.",funFact:"Carnival dances include the Funkenmariechen, a female solo dancer in military costume. Some Tanz traditions go back centuries."},
{type:"teach",trg:"der S\u00e4nger",src:"the singer (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'singen' + '-er' (agent suffix).\nCarnival S\u00e4nger perform songs that become annual hits.",example:"A: Wer ist der S\u00e4nger auf der B\u00fchne?\nB: Das ist ein ber\u00fchmter Karnevalss\u00e4nger.\nA: Er singt wahnsinnig gut!\nB: Seine Lieder kennt jeder in K\u00f6ln.",exampleSrc:"A: Who is the singer on stage?\nB: That's a famous carnival singer.\nA: He sings insanely well!\nB: Everyone in Cologne knows his songs.",funFact:"Carnival S\u00e4nger perform original songs that become annual hits. The best ones are remembered for decades across the Rhineland."},
{type:"teach",trg:"die S\u00e4ngerin",src:"the singer (female)",pos:"noun",gender:"f",note:"Feminine noun. S\u00e4nger + '-in.'\nThe -er/-erin pattern works for all agent nouns.",example:"A: Die S\u00e4ngerin hat eine tolle Stimme.\nB: Ja, sie ist die beste im ganzen Rheinland.\nA: Kennst du ihre Lieder?\nB: Nat\u00fcrlich! Alle singen mit.",exampleSrc:"A: The singer has a great voice.\nB: Yes, she's the best in the whole Rhineland.\nA: Do you know her songs?\nB: Of course! Everyone sings along.",funFact:"The -er/-erin pattern works for all agent nouns. You already know Lehrer/Lehrerin, Spieler/Spielerin. Same system every time."},
{type:"mc",q:"Auf welcher Struktur steht die Band beim Karneval?",opts:["auf der Bühne","vor dem ganzen Publikum","auf der großen Flöte","auf dem Tanz"],ans:"auf der Bühne",hint:"A raised platform where performers stand. Feminine noun from Middle High German."},
{type:"fb",s:"Beim {1} bewegen sich alle Zuschauer zur Musik.",a:["Tanz"],opts:["Tanz","Saal","Publikum","Auftritt"],hint:"Which masculine noun means 'dance,' from Old French 'danse'?",sSrc:"During the dance all spectators move to the music."},
{type:"teach",trg:"der Musiker",src:"the musician (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Musik' + '-er.'\nCarnival bands play brass-heavy music that gets entire streets moving.",example:"A: Der Musiker spielt Trompete.\nB: Und der andere spielt Trommel.\nA: Die Musik ist so mitrei\u00dfend!\nB: Karnevalsmusiker sind echte Profis.",exampleSrc:"A: The musician plays trumpet.\nB: And the other one plays drums.\nA: The music is so captivating!\nB: Carnival musicians are real professionals.",funFact:"Carnival bands (Kapellen) play brass-heavy music that gets entire streets moving. Being a Karnevalsmusiker is a respected tradition."},
{type:"teach",trg:"die Musikerin",src:"the musician (female)",pos:"noun",gender:"f",note:"Feminine noun. Musiker + '-in.'\nThe pattern is reliable: Musiker/Musikerin, K\u00fcnstler/K\u00fcnstlerin.",example:"A: Die Musikerin spielt Fl\u00f6te.\nB: Sie ist wirklich talentiert.\nA: Seit wann spielt sie?\nB: Seit sie ein Kind war.",exampleSrc:"A: The musician plays flute.\nB: She is really talented.\nA: How long has she been playing?\nB: Since she was a child.",funFact:"The -ler/-lerin pattern: Musiker/Musikerin, K\u00fcnstler/K\u00fcnstlerin, Sportler/Sportlerin. German builds profession pairs reliably."},
{type:"teach",trg:"die Oper",src:"the opera",pos:"noun",gender:"f",note:"Feminine noun. From Italian 'opera' (work).\nCologne has the Oper K\u00f6ln, one of Germany's largest opera houses.",example:"A: Warst du schon mal in der Oper?\nB: Ja, einmal in der Oper K\u00f6ln.\nA: W\u00e4hrend des Karnevals?\nB: Ja! Sogar die Oper macht beim Karneval mit.",exampleSrc:"A: Have you ever been to the opera?\nB: Yes, once at the Cologne Opera.\nA: During carnival?\nB: Yes! Even the opera joins in during carnival.",funFact:"Cologne has the Oper K\u00f6ln, one of Germany's largest opera houses. During Karneval season, even the opera gets into the spirit."},
{type:"teach",trg:"das Orchester",src:"the orchestra",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'orchestra' (dancing place).\nKarneval uses everything from full Orchester to tiny street bands.",example:"A: H\u00f6rst du das Orchester?\nB: Ja, sie spielen Karnevalsmusik!\nA: Ein ganzes Orchester auf der Stra\u00dfe!\nB: Das gibt es nur beim Karneval.",exampleSrc:"A: Do you hear the orchestra?\nB: Yes, they're playing carnival music!\nA: A whole orchestra on the street!\nB: That only happens at carnival.",funFact:"From Greek 'orchestra' (dancing place). Karneval uses everything from full Orchester to tiny street bands."},
{type:"teach",trg:"die Fl\u00f6te",src:"the flute",pos:"noun",gender:"f",note:"Feminine noun. From Old French 'flaute.'\n'Blockfl\u00f6te' (recorder) is the instrument every German child learns first.",example:"A: Was ist das f\u00fcr ein Instrument?\nB: Das ist eine Fl\u00f6te.\nA: Der Klang ist so sch\u00f6n.\nB: Fl\u00f6ten geh\u00f6ren zu jedem Karnevalszug.",exampleSrc:"A: What kind of instrument is that?\nB: That's a flute.\nA: The sound is so beautiful.\nB: Flutes belong to every carnival parade.",funFact:"In carnival parades, you hear Fl\u00f6ten alongside drums and brass. 'Blockfl\u00f6te' (recorder) is the instrument every German child learns first."},
{type:"match",pairs:[{trg:"die Musikerin",src:"the musician (female)"},{trg:"die Oper",src:"the opera"},{trg:"das Orchester",src:"the orchestra"},{trg:"die Fl\u00f6te",src:"the flute"}]},
{type:"teach",trg:"das Publikum",src:"the audience",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'publicum' (the public).\nAt Karneval, the line between Publikum and performers blurs.",example:"A: Das Publikum ist begeistert!\nB: Alle klatschen und singen mit.\nA: Wo h\u00f6rt das Publikum auf und wo fangen die K\u00fcnstler an?\nB: Beim Karneval gibt es keinen Unterschied.",exampleSrc:"A: The audience is thrilled!\nB: Everyone is clapping and singing along.\nA: Where does the audience end and the artists begin?\nB: At carnival there's no difference.",funFact:"At Karneval, the line between Publikum and performers blurs completely. Everyone sings along, everyone dances, everyone is part of the show."},
{type:"fb",s:"H\u00f6rst du das {1}? Sie spielen Karnevalsmusik auf der Stra\u00dfe!",a:["Orchester"],opts:["Orchester","Publikum","Fl\u00f6te","B\u00fchne"],hint:"A large musical ensemble with many instruments, named from an ancient Greek word for the dancing area in front of the stage.",sSrc:"Do you hear the orchestra? They are playing carnival music on the street!"},
{type:"mc",q:"Ein S\u00e4nger singt. Eine S\u00e4ngerin singt auch. Was bildet die weibliche Form?",opts:["S\u00e4nger + -erin","S\u00e4nger + -in","S\u00e4ng + -erin","Sing + -erin"],ans:"S\u00e4nger + -in",hint:"The standard German pattern adds a specific suffix to the masculine form to create the feminine."}
]},
{id:"deu_r17l2b",title:"Masken und Melodien (Teil 2)",icon:"\uD83C\uDFB6",xp:15,board:true,steps:[
{type:"intro",title:"Masken und Melodien (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Auftritt",src:"the performance, the appearance",pos:"noun",gender:"m",note:"Masculine noun. Auf (on/up) + Tritt (step).\nLiterally 'stepping onto' the stage.",example:"A: Der Auftritt war fantastisch!\nB: Ja, die Band hat alles gegeben.\nA: Wann ist der n\u00e4chste Auftritt?\nB: In einer Stunde auf der gro\u00dfen B\u00fchne.",exampleSrc:"A: The performance was fantastic!\nB: Yes, the band gave it their all.\nA: When is the next performance?\nB: In one hour on the main stage.",funFact:"Literally 'stepping up onto' the stage. An appearance, a performance. Whether on stage or entering a room, it is always an Auftritt."},
{type:"teach",trg:"der Saal",src:"the hall, the ballroom",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'sal.'\nPlural: S\u00e4le. One of the few German words with this unusual plural.",example:"A: Der Saal ist voll!\nB: \u00dcber tausend Menschen in einem Saal.\nA: Die Stimmung ist unglaublich.\nB: Karnevalss\u00e4le sind immer ausverkauft.",exampleSrc:"A: The hall is full!\nB: Over a thousand people in one hall.\nA: The atmosphere is incredible.\nB: Carnival halls are always sold out.",funFact:"Karneval 'Sitzungen' happen in large S\u00e4le (plural). The biggest hold thousands of costumed revelers. Saal is one of the few German words with the plural S\u00e4le."},
{type:"teach",trg:"musikalisch",src:"musical",pos:"adj",gender:null,note:"From Musik + '-alisch.'\n'Sie ist sehr musikalisch' (She is very musical).",example:"A: Bist du musikalisch?\nB: Ein bisschen. Ich spiele Gitarre.\nA: Das Rheinland ist sehr musikalisch.\nB: Hier singt man \u00fcberall, sogar in der Kneipe.",exampleSrc:"A: Are you musical?\nB: A little. I play guitar.\nA: The Rhineland is very musical.\nB: Here people sing everywhere, even in the pub.",funFact:"The Rhineland is Germany's most musikalisch region. People sing at pubs, parades, and train stations during Karneval."},
{type:"teach",trg:"popul\u00e4r",src:"popular",pos:"adj",gender:null,note:"From Latin 'popularis.' Same as English.\nStress falls on the last syllable: po-pu-L\u00c4R.",example:"A: Dieses Lied ist sehr popul\u00e4r.\nB: Ja, jeder kennt es!\nA: Wie hei\u00dft es?\nB: 'Viva Colonia.' Der popul\u00e4rste Karnevalsschlager.",exampleSrc:"A: This song is very popular.\nB: Yes, everyone knows it!\nA: What's it called?\nB: 'Viva Colonia.' The most popular carnival hit.",funFact:"'Viva Colonia' is one of the most popul\u00e4r Karnevalslieder ever. Karneval songs become national hits that people sing for decades."},
{type:"teach",trg:"traditionell",src:"traditional",pos:"adj",gender:null,note:"Tradition + '-ell.' Karneval is both traditionell and modern.\nOld Sitzung format coexists with techno floats.",example:"A: Ist das ein traditionelles Lied?\nB: Ja, schon \u00fcber hundert Jahre alt.\nA: Aber die Band spielt es modern.\nB: Traditionell und modern, das passt zusammen.",exampleSrc:"A: Is that a traditional song?\nB: Yes, over a hundred years old.\nA: But the band plays it in a modern way.\nB: Traditional and modern, that fits together.",funFact:"Karneval is both traditionell and modern. The old Sitzung format coexists with techno floats and hip-hop acts."},
{type:"mc",q:"Das Publikum klatscht und singt mit. Wie beschreibt man die Musik?",opts:["populär und traditionell","sehr still und äußerst ernst","langweilig und leise","traurig und langsam"],ans:"populär und traditionell",hint:"Carnival songs are both widely recognized (from Latin roots) and rooted in old customs."},
{type:"fb",s:"Der Saal war voll. \u00dcber tausend Menschen haben den {1} der Band gefeiert.",a:["Auftritt"],opts:["Auftritt","Saal","Tanz","Publikum"],hint:"Which masculine noun means a performance or appearance on stage? Literally 'stepping onto.'",sSrc:"The hall was full. Over a thousand people celebrated the band's performance."},
{type:"teach",trg:"elegant",src:"elegant",pos:"adj",gender:null,note:"Same as English, from French.\nSome carnival events demand elegante Kost\u00fcme.",example:"A: Dein Kost\u00fcm ist sehr elegant.\nB: Danke! Es ist ein Prinzessinnenkleid.\nA: Elegant und trotzdem Karneval.\nB: Man kann beides sein!",exampleSrc:"A: Your costume is very elegant.\nB: Thanks! It's a princess dress.\nA: Elegant and still carnival.\nB: You can be both!",funFact:"Some carnival events demand elegante costumes. The Prinzenpaar (carnival prince and princess) wear regal outfits. Elegant is the opposite of the street chaos."},
{type:"teach",trg:"schick",src:"stylish, chic",pos:"adj",gender:null,note:"Borrowed from French 'chic.'\n'Das Kost\u00fcm ist sehr schick!' Implies taste and effort.",example:"A: Du siehst schick aus!\nB: Findest du? Nur ein einfaches Kost\u00fcm.\nA: Aber sehr schick gemacht.\nB: Danke, das ist nett von dir.",exampleSrc:"A: You look stylish!\nB: You think? Just a simple costume.\nA: But very stylishly done.\nB: Thanks, that's nice of you.",funFact:"Borrowed from French 'chic.' A schick costume gets compliments. A verr\u00fcckt costume gets laughs. Both are welcome at Karneval."},
{type:"teach",trg:"am\u00fcsieren",src:"to amuse, to have fun",pos:"verb",gender:null,note:"From French 'amuser.' Reflexive: sich am\u00fcsieren.\n'Wir haben uns k\u00f6stlich am\u00fcsiert' (We had a wonderful time).",example:"A: Am\u00fcsierst du dich?\nB: Ja, ich am\u00fcsiere mich k\u00f6stlich!\nA: Das freut mich.\nB: Karneval ist zum Am\u00fcsieren gemacht.",exampleSrc:"A: Are you having fun?\nB: Yes, I'm having a wonderful time!\nA: I'm glad.\nB: Carnival is made for having fun.",funFact:"The core purpose of Karneval: sich am\u00fcsieren. 'Wir haben uns k\u00f6stlich am\u00fcsiert' is one of the most satisfying German sentences."},
{type:"teach",trg:"l\u00e4cheln",src:"to smile",pos:"verb",gender:null,note:"The diminutive form of 'lachen' (to laugh).\nThe '-eln' ending makes it softer: a gentle smile, not a full laugh.",example:"A: Warum l\u00e4chelst du?\nB: Weil alles so sch\u00f6n ist.\nA: Du l\u00e4chelst seit einer Stunde.\nB: Karneval macht das mit mir.",exampleSrc:"A: Why are you smiling?\nB: Because everything is so beautiful.\nA: You've been smiling for an hour.\nB: Carnival does that to me.",funFact:"The diminutive form of 'lachen' (to laugh). The '-eln' ending softens it: not a full laugh, but a gentle smile. 'Sie l\u00e4chelt' is one of the most beautiful German sentences."},
{type:"teach",trg:"klingen",src:"to sound",pos:"verb",gender:null,note:"Irregular: klingt, klang, geklungen.\nRelated to English 'cling' and 'clang.'",example:"A: Die Musik klingt fantastisch!\nB: Ja, das Orchester klingt wunderbar.\nA: Alles klingt nach Karneval.\nB: Musik, Lachen, Gl\u00e4ser, Konfetti.",exampleSrc:"A: The music sounds fantastic!\nB: Yes, the orchestra sounds wonderful.\nA: Everything sounds like carnival.\nB: Music, laughter, glasses, confetti.",funFact:"Irregular: klingt, klang, geklungen. Related to English 'cling' and 'clang.' At Karneval, everything klingt: music, laughter, glasses."},
{type:"mc",q:"Die Band betritt die B\u00fchne. Was bedeutet 'Auftritt'?",opts:["ein Orchester","eine Melodie","ein Tanz","ein Auftritt auf der B\u00fchne"],ans:"ein Auftritt auf der B\u00fchne",hint:"The band enters the performance surface. What do you call a public appearance by a performer?"},
{type:"mc",q:"Wenn ein m\u00e4nnlicher Musiker 'der Musiker' ist, was ist eine weibliche Musikerin?",opts:["die Musiker","die Musikerin","der Musikerin (nein)","das Musikerin"],ans:"die Musikerin",hint:"German forms feminine professions with a standard suffix. Which option has both the correct article and feminine ending?"},
{type:"fb",s:"Die Musik {1} fantastisch!",a:["klingt"],opts:["klingt","klingen","schaut","l\u00e4chelt"],hint:"Which verb describes how music reaches your ears?",sSrc:"The music sounds fantastic!"},
{type:"match",pairs:[{trg:"B\u00fchne",src:"stage"},{trg:"Publikum",src:"audience"},{trg:"Auftritt",src:"performance"},{trg:"Saal",src:"hall"}]},
{type:"mc",q:"Was bedeutet 'musikalisch'?",opts:["the hall, the ballroom","the dance","musical","traditional"],ans:"musical",hint:"From Musik + -alisch. Having talent or relating to the art of melody and rhythm."},
{type:"fb",s:"Dein Kost\\u00fcm ist sehr {1}.",a:["elegant"],opts:["die Musikerin","der Saal","die B\\u00fchne","elegant"],hint:"A French/Latin cognate. Describes something refined, tasteful, and graceful in style.",sSrc:"Your costume is very elegant."},
{type:"mc",q:"Was bedeutet 'schick'?",opts:["elegant","the opera","the singer (male)","stylish, chic"],ans:"stylish, chic",hint:"French loanword. Describes fashionable, tasteful, well-dressed appearance."}
]},

// ─── Lesson 3: Jeder ist du ──────────────────────────────────
{id:"deu_r17l3",title:"Jeder ist du",icon:"\uD83E\uDD1D",xp:15,board:true,steps:[
{type:"intro",title:"Jeder ist du",desc:"During Karneval the rules are suspended. Strangers say 'du.' People dress up to be someone else. Learn costume and character vocabulary and the um...zu construction.",goals:["Learn vocabulary for costumes and characters","Understand the um...zu construction (purpose)","Discover why Karneval suspends Germany's formality"]},
{type:"teach",trg:"der Held",src:"the hero",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'helid' (warrior).\nCarnival is full of Helden: superheroes, knights, fairy tale princes.",example:"A: Als wer bist du verkleidet?\nB: Als Superheld!\nA: Jeder will ein Held sein.\nB: Beim Karneval kann jeder ein Held sein.",exampleSrc:"A: Who are you dressed up as?\nB: As a superhero!\nA: Everyone wants to be a hero.\nB: At carnival everyone can be a hero.",funFact:"From Old High German 'helid' (warrior). Related to English 'hold' in its original sense of bravery. The costume makes the Held."},
{type:"teach",trg:"die Heldin",src:"the hero (female)",pos:"noun",gender:"f",note:"Feminine noun. Held + '-in.'\nWonder Woman, Pippi Langstrumpf, Cleopatra: popular carnival Heldinnen.",example:"A: Tolles Kost\u00fcm! Wer bist du?\nB: Ich bin eine Heldin aus einem M\u00e4rchen.\nA: Welche Heldin?\nB: Rosenrot! Aus 'Schneewittchen und Rosenrot.'",exampleSrc:"A: Great costume! Who are you?\nB: I'm a heroine from a fairy tale.\nA: Which heroine?\nB: Rose Red! From 'Snow White and Rose Red.'",funFact:"The -in pattern even works on ancient words like Held. Wonder Woman, Cleopatra, and Pippi Langstrumpf are all popular carnival Heldinnen."},
{type:"teach",trg:"der K\u00fcnstler",src:"the artist (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Kunst' (art) + '-ler.'\nProfessional K\u00fcnstler design the massive parade floats.",example:"A: Wer hat diesen Wagen gebaut?\nB: Ein Team von K\u00fcnstlern.\nA: Das ist echte Kunst!\nB: Die K\u00fcnstler arbeiten monatelang daran.",exampleSrc:"A: Who built this float?\nB: A team of artists.\nA: That's real art!\nB: The artists work on it for months.",funFact:"Carnival is art. Professional K\u00fcnstler design the massive parade floats months in advance. Some floats are genuine political masterpieces."},
{type:"teach",trg:"die K\u00fcnstlerin",src:"the artist (female)",pos:"noun",gender:"f",note:"Feminine noun. K\u00fcnstler + '-in.'\nThe -ler/-lerin pattern: Sportler/Sportlerin, K\u00fcnstler/K\u00fcnstlerin.",example:"A: Die K\u00fcnstlerin hat die Masken gemalt.\nB: Sie ist unglaublich talentiert.\nA: Jede Maske ist ein Kunstwerk.\nB: Die K\u00fcnstlerin hat drei Wochen daf\u00fcr gebraucht.",exampleSrc:"A: The artist painted the masks.\nB: She is incredibly talented.\nA: Every mask is a work of art.\nB: The artist needed three weeks for them.",funFact:"The -ler/-lerin pattern: K\u00fcnstler/K\u00fcnstlerin, Sportler/Sportlerin. German builds profession pairs as reliably as compound nouns."},
{type:"teach",trg:"die Rolle",src:"the role",pos:"noun",gender:"f",note:"Feminine noun. From French 'role' (originally a scroll with an actor's lines).\n'Welche Rolle spielst du?' is the standard Karneval question.",example:"A: Welche Rolle spielst du heute?\nB: Ich bin ein r\u00f6mischer Senator.\nA: Die Rolle passt zu dir!\nB: Beim Karneval spielt jeder eine Rolle.",exampleSrc:"A: What role are you playing today?\nB: I'm a Roman senator.\nA: The role suits you!\nB: At carnival everyone plays a role.",funFact:"At Karneval, your costume IS your Rolle. 'Welche Rolle spielst du?' is the standard question at every carnival party."},
{type:"mc",q:"Wer hat die riesigen Karnevalswagen gebaut?",opts:["die Helden","K\u00fcnstler","die Figuren","die Heldinnen"],ans:"K\u00fcnstler",hint:"Professional artists who design floats months in advance. From Kunst (art) + -ler."},
{type:"fb",s:"Beim Karneval spielt jeder eine {1}. Du bist nicht du selbst.",a:["Rolle"],opts:["Rolle","Figur","Szene","Fantasie"],hint:"From French 'role.' Which feminine noun means the part you play, originally a scroll with an actor's lines?",sSrc:"At carnival everyone plays a role. You are not yourself."},
{type:"teach",trg:"die Figur",src:"the character, the figure",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'figura.'\n'Eine interessante Figur' means a character in a story OR an interesting person.",example:"A: Welche Figur bist du?\nB: Eine Figur aus einem Comic.\nA: Ich erkenne die Figur nicht.\nB: Das ist auch egal. Hauptsache bunt!",exampleSrc:"A: Which character are you?\nB: A character from a comic.\nA: I don't recognize the character.\nB: That doesn't matter. Main thing is colorful!",funFact:"At Karneval, everyone becomes a Figur. 'Eine interessante Figur' can mean a fictional character OR a fascinating real person."},
{type:"teach",trg:"die Szene",src:"the scene",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'skene' (tent, stage backdrop).\nDie Karnevalsszene = the entire carnival subculture.",example:"A: Das ist eine tolle Szene!\nB: Ja, die Altstadt ist eine einzige gro\u00dfe Szene.\nA: Wie im Theater.\nB: Genau, und jeder spielt mit.",exampleSrc:"A: What a great scene!\nB: Yes, the Old Town is one big scene.\nA: Like in a theater.\nB: Exactly, and everyone plays along.",funFact:"Also means a social milieu. 'Die Karnevalsszene' is the entire carnival subculture: the societies, the traditions, the insiders."},
{type:"teach",trg:"die Puppe",src:"the doll, the puppet",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'pupa.'\nCarnival floats often feature giant Puppen of politicians.",example:"A: Schau, diese riesige Puppe auf dem Wagen!\nB: Das ist ein Politiker!\nA: Als Puppe auf einem Karnevalswagen?\nB: Ja, das ist politische Satire.",exampleSrc:"A: Look at that giant puppet on the float!\nB: That's a politician!\nA: As a puppet on a carnival float?\nB: Yes, that's political satire.",funFact:"Carnival floats often feature giant Puppen of politicians and celebrities. Being turned into a Karnevalspuppe means you are famous enough to mock."},
{type:"teach",trg:"das M\u00e4rchen",src:"the fairy tale",pos:"noun",gender:"n",note:"Neuter noun because of the -chen ending.\nFrom 'M\u00e4r' (tale) + '-chen' (diminutive).",example:"A: Als wer bist du verkleidet?\nB: Als Prinz aus einem M\u00e4rchen!\nA: Welches M\u00e4rchen?\nB: Dornr\u00f6schen. Aber ich bin der Prinz.",exampleSrc:"A: Who are you dressed up as?\nB: A prince from a fairy tale!\nA: Which fairy tale?\nB: Sleeping Beauty. But I'm the prince.",funFact:"Grimm's M\u00e4rchen (Cinderella, Snow White, Hansel and Gretel) are Germany's biggest cultural export after cars and beer. The -chen ending always makes nouns neuter."},
{type:"teach",trg:"die Fantasie",src:"the imagination, the fantasy",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'phantasia.'\nGerman spells it with F, not Ph.",example:"A: Das Kost\u00fcm ist pure Fantasie!\nB: Danke! Fantasie ist alles beim Karneval.\nA: Ohne Fantasie kein Kost\u00fcm.\nB: Genau. Fantasie ist das Wichtigste.",exampleSrc:"A: The costume is pure imagination!\nB: Thanks! Imagination is everything at carnival.\nA: Without imagination, no costume.\nB: Exactly. Imagination is the most important thing.",funFact:"German spells it Fantasie with F, not Ph. Karneval is where German Fantasie breaks free from German Ordnung (order)."},
{type:"match",pairs:[{trg:"der Held",src:"the hero"},{trg:"die Rolle",src:"the role"},{trg:"das Märchen",src:"the fairy tale"},{trg:"die Fantasie",src:"the imagination"}]},
{type:"mc",q:"Was bedeutet 'die Puppe' auf Englisch?",opts:["the doll, the puppet","the performing artist","the theatrical scene","the fictional character"],ans:"the doll, the puppet",hint:"Carnival floats feature giant versions of these. Politicians become giant Puppen."}
]},

// --- Lesson: Gefuehle und Feste ---
{id:"deu_r17l4",title:"Gefuehle und Feste",icon:"💄",xp:15,board:true,steps:[
{type:"intro",title:"Gefuehle und Feste",desc:"Adjectives for describing people and moments: relaxed, pretty, great. Plus verbs for celebration: hugging, decorating, kissing.",goals:["Learn personality adjectives","Master celebration verbs","Describe people and events"]},
{type:"teach",trg:"locker",src:"relaxed, casual",pos:"adj",gender:null,note:"'Locker bleiben!' (Stay relaxed!)\nThe Rhineland attitude is locker, warm and informal.",example:"A: Die Stimmung hier ist so locker.\nB: Ja, das Rheinland ist locker.\nA: Anders als in Berlin.\nB: Berlin ist cool, das Rheinland ist warm.",exampleSrc:"A: The atmosphere here is so relaxed.\nB: Yes, the Rhineland is relaxed.\nA: Different from Berlin.\nB: Berlin is cool, the Rhineland is warm.",funFact:"The Rhineland attitude is locker. Berlin is cool. Both are informal, but locker is warm where Berlin coolness is reserved."},
{type:"teach",trg:"prima",src:"great, excellent",pos:"adj",gender:null,note:"From Latin 'prima' (first/best). Colloquial and positive.\n'Prima!' on its own means 'Great!'",example:"A: Wie findest du den Karneval?\nB: Prima! Einfach prima!\nA: Ich bin froh, dass es dir gef\u00e4llt.\nB: Gef\u00e4llt? Ich bin begeistert!",exampleSrc:"A: How do you like the carnival?\nB: Great! Simply great!\nA: I'm glad you like it.\nB: Like it? I'm thrilled!",funFact:"From Latin 'prima' (first/best). No declension, no complications. One of the easiest German adjectives to use."},
{type:"teach",trg:"klasse",src:"great, awesome",pos:"adj",gender:null,note:"Used as an indeclinable adjective.\n'Das Kost\u00fcm ist klasse!' Very colloquial.",example:"A: Das Kost\u00fcm ist klasse!\nB: Findest du? Nur zusammengeklebt.\nA: Gerade deshalb ist es klasse.\nB: Kreativit\u00e4t schl\u00e4gt Geld.",exampleSrc:"A: The costume is awesome!\nB: You think? Just glued together.\nA: That's exactly why it's awesome.\nB: Creativity beats money.",funFact:"From 'Klasse' (class) used informally. Like English 'classy' shortened to express pure quality. Indeclinable, no endings needed."},
{type:"teach",trg:"h\u00fcbsch",src:"pretty, attractive",pos:"adj",gender:null,note:"From Middle High German 'h\u00fcbesch' (courtly).\nGentler than 'sch\u00f6n,' implies charm rather than grandeur.",example:"A: Das ist ein h\u00fcbsches Kost\u00fcm!\nB: Danke! Nicht sch\u00f6n, aber h\u00fcbsch.\nA: Was ist der Unterschied?\nB: H\u00fcbsch ist charmant, sch\u00f6n ist gro\u00df.",exampleSrc:"A: That's a pretty costume!\nB: Thanks! Not beautiful, but pretty.\nA: What's the difference?\nB: Pretty is charming, beautiful is grand.",funFact:"From Middle High German 'h\u00fcbesch' (courtly). H\u00fcbsch implies charm rather than grandeur. Gentler and more personal than 'sch\u00f6n.'"},
{type:"teach",trg:"intensiv",src:"intensive, intense",pos:"adj",gender:null,note:"Same as English, from Latin 'intensivus.'\nStress on the last syllable: in-ten-SIV.",example:"A: Das war ein intensiver Tag!\nB: Ja, alle Sinne auf einmal.\nA: Die Farben, der L\u00e4rm, die Emotionen.\nB: Karneval ist ein intensives Erlebnis.",exampleSrc:"A: That was an intense day!\nB: Yes, all senses at once.\nA: The colors, the noise, the emotions.\nB: Carnival is an intense experience.",funFact:"Karneval is intensiv: the colors, the noise, the emotions. 'Ein intensives Erlebnis' (an intense experience)."},
{type:"fb",s:"Die Stimmung beim Karneval ist {1}. Alle sind gl\u00fccklich und entspannt.",a:["locker"],opts:["locker","intensiv","h\u00fcbsch","klasse"],hint:"Which adjective means relaxed and casual? The Rhineland attitude is famously this.",sSrc:"The atmosphere at carnival is relaxed. Everyone is happy and laid-back."},
{type:"mc",q:"Mia fragt: 'Wie findest du den Karneval?' Verumius antwortet begeistert. Welches Wort passt?",opts:["Prima!","Klasse!","H\u00fcbsch!","Intensiv!"],ans:"Prima!",hint:"A very common Italian-origin exclamation of approval used in German. Hannelore uses it here to cheer someone up."},
{type:"teach",trg:"umarmen",src:"to hug",pos:"verb",gender:null,note:"Um- (around) + Arme (arms). Literally 'to put arms around.'\nDuring Karneval, strangers umarmen each other.",example:"A: Der Fremde hat mich umarmt!\nB: Das ist normal beim Karneval.\nA: In Berlin w\u00fcrde niemand das tun.\nB: Beim Karneval umarmt man alle.",exampleSrc:"A: The stranger hugged me!\nB: That's normal at carnival.\nA: In Berlin nobody would do that.\nB: At carnival you hug everyone.",funFact:"During Karneval, strangers umarmen each other freely. Try it on a normal Tuesday in Germany and watch the horror."},
{type:"teach",trg:"schminken",src:"to apply makeup, to paint (face)",pos:"verb",gender:null,note:"Reflexive: sich schminken (to put makeup on yourself).\nAt Karneval, schminken is an art form.",example:"A: Hast du dich geschminkt?\nB: Ja, ich bin eine Katze!\nA: Die Schminke sieht toll aus.\nB: Danke, ich habe eine Stunde gebraucht.",exampleSrc:"A: Did you do your face paint?\nB: Yes, I'm a cat!\nA: The makeup looks great.\nB: Thanks, it took me an hour.",funFact:"At Karneval, schminken is an art form. Entire faces become cats, clowns, or abstract art. Even grown men schminken themselves without embarrassment."},
{type:"teach",trg:"dekorieren",src:"to decorate",pos:"verb",gender:null,note:"From French 'd\u00e9corer.' Streets and pubs are dekoriert for weeks.\nThe decoration budget in Cologne runs into millions.",example:"A: Wer hat die Stra\u00dfe dekoriert?\nB: Die Anwohner! Jedes Haus ist geschm\u00fcckt.\nA: Wochenlang dekorieren sie alles.\nB: Karneval ist Gemeinschaftsarbeit.",exampleSrc:"A: Who decorated the street?\nB: The residents! Every house is decorated.\nA: They decorate everything for weeks.\nB: Carnival is a community effort.",funFact:"Streets, buildings, and pubs are dekoriert for weeks before Karneval. The decoration budget in Cologne alone runs into millions of euros."},
{type:"teach",trg:"k\u00fcssen",src:"to kiss",pos:"verb",gender:null,note:"A 'B\u00fctzchen' (little kiss on the cheek) between strangers is acceptable at Karneval.\nOn any other day it would be completely inappropriate.",example:"A: Hat sie mich gerade gek\u00fcsst?\nB: Ja, das war ein B\u00fctzchen. Normal beim Karneval.\nA: Einfach so? Einen Fremden?\nB: Willkommen im Rheinland!",exampleSrc:"A: Did she just kiss me?\nB: Yes, that was a B\u00fctzchen. Normal at carnival.\nA: Just like that? A stranger?\nB: Welcome to the Rhineland!",funFact:"The 'B\u00fctzchen' (Rhineland dialect for a little kiss on the cheek) between strangers is acceptable during Karneval. On any other day it would be assault."},
{type:"teach",trg:"der Kuss",src:"the kiss",pos:"noun",gender:"m",note:"Masculine noun. Plural: K\u00fcsse (with Umlaut).\nThe 'B\u00fctzchen' is the gentlest carnival tradition.",example:"A: Was ist ein B\u00fctzchen?\nB: Ein kleiner Kuss auf die Wange.\nA: Im Rheinland ist das normal?\nB: Nur beim Karneval. Sonst nicht.",exampleSrc:"A: What is a B\u00fctzchen?\nB: A little kiss on the cheek.\nA: In the Rhineland that's normal?\nB: Only at carnival. Otherwise not.",funFact:"The noun from k\u00fcssen. Plural: K\u00fcsse (with Umlaut). The B\u00fctzchen (Rhineland dialect for Kuss) is the gentlest carnival tradition."},
{type:"mc",q:"Der Fremde hat Verumius einfach umarmt. Was bedeutet 'umarmen'?",opts:["schminken","die Arme um jemanden legen","dekorieren","k\u00fcssen"],ans:"die Arme um jemanden legen",hint:"A compound verb meaning to embrace. The prefix suggests wrapping around, the root refers to limbs."},
{type:"fb",s:"Hast du dich f\u00fcr den Karneval {1}? Du siehst aus wie eine Katze!",a:["geschminkt"],opts:["geschminkt","dekoriert","gek\u00fcsst","umarmt"],hint:"Which past participle means 'applied face paint or makeup'? Reflexive: sich schminken.",sSrc:"Did you do your face paint for carnival? You look like a cat!"},
{type:"teach",trg:"um",src:"in order to (with zu + infinitive)",pos:"part",gender:null,note:"As particle in um...zu constructions: expresses purpose.\n'Ich lerne, um Deutsch zu sprechen.'",example:"A: Warum lernst du Deutsch?\nB: Um in Deutschland zu arbeiten.\nA: Und warum fährst du nach Köln?\nB: Um Karneval zu feiern!",exampleSrc:"A: Why are you learning German?\nB: In order to work in Germany.\nA: And why are you going to Cologne?\nB: In order to celebrate carnival!",funFact:"Um has many faces: as a preposition it means around (um die Ecke). In um...zu constructions it means in order to. Combined with zu + infinitive, it creates German purpose clauses."},
{type:"tip",title:"um...zu: Expressing Purpose",text:"When you want to say WHY someone does something, use um...zu plus an infinitive.\n\nThe main clause comes first, then um opens the purpose clause, and zu plus the infinitive close it.\n\n- Man verkleidet sich, um eine andere Person zu sein.\n  (One dresses up in order to be a different person.)\n- Wir fahren nach Köln, um Karneval zu feiern.\n  (We travel to Cologne in order to celebrate carnival.)\n- Ich lerne, um Deutsch zu sprechen.\n  (I learn in order to speak German.)\n\nImportant rule: The subject in both parts must be the same.\nThink of 'um' as 'in order' and 'zu' as 'to.'",deepDive:{title:"um...zu with Separable Verbs",text:"With separable verbs, 'zu' goes between prefix and verb:\n\nanziehen: um anzuziehen (in order to put on)\naussehen: um auszusehen (in order to look)\nmitmachen: um mitzumachen (in order to join in)\n\n'Er verkleidet sich, um gut auszusehen.'\n(He dresses up in order to look good.)\n\nThe 'zu' slides into the middle of the verb."}},
{type:"mc",q:"Verumius verkleidet sich. Er will ein r\u00f6mischer Senator sein. Wie sagt man das mit um...zu?",opts:["Verumius verkleidet sich, statt ein Senator zu sein","Verumius verkleidet sich, ohne ein Senator zu sein","Verumius verkleidet sich, um ein Senator zu sein","Verumius verkleidet sich, weil er ein Senator ist"],ans:"Verumius verkleidet sich, um ein Senator zu sein",hint:"Um...zu expresses purpose: doing X in order to achieve Y. Same subject in both parts."},
{type:"fb",s:"Wir fahren nach K\u00f6ln, {1} Karneval zu feiern.",a:["um"],opts:["um","ohne","statt","damit"],hint:"Which word introduces a purpose clause meaning 'in order to'?",sSrc:"We travel to Cologne in order to celebrate carnival."},
{type:"mc",q:"Verumius tr\u00e4gt eine Toga. Welche Rolle spielt er?",opts:["Einen Piraten","Einen r\u00f6mischen Senator","Eine M\u00e4rchenfigur","Einen Helden"],ans:"Einen r\u00f6mischen Senator",hint:"Think about what Verumius actually IS. His costume is biographical."},
{type:"mc",q:"Sie gab ihm einen ___ auf die Wange. Wie süß!",opts:["Hut","Bart","Schmuck","Kuss"],ans:"Kuss",hint:"A masculine noun for a physical gesture of affection placed on someone's cheek."}
]},

// ─── Lesson 4: Warum? Wozu? Stattdessen! ─────────────────────
{id:"deu_r17l5",title:"Warum? Wozu? Stattdessen!",icon:"\uD83D\uDCA1",xp:15,board:true,steps:[
{type:"intro",title:"Warum? Wozu? Stattdessen!",desc:"Four infinitive clause constructions: um...zu, ohne...zu, (an)statt...zu, and damit. Learn when to use which, and practice them with sports and carnival vocabulary.",goals:["Master all four infinitive clause constructions","Understand the difference between um...zu and damit","Learn sports and games vocabulary"]},
{type:"teach",trg:"der Spieler",src:"the player (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'spielen' (to play) + '-er.'\n'Spieler' without context usually means football player.",example:"A: Der Spieler hat ein Tor geschossen!\nB: Welcher Spieler?\nA: Die Nummer 9. Ein toller Spieler.\nB: Fu\u00dfballspieler sind in Deutschland Helden.",exampleSrc:"A: The player scored a goal!\nB: Which player?\nA: Number 9. A great player.\nB: Football players are heroes in Germany.",funFact:"Whether football, cards, or carnival games, a Spieler is anyone who plays. 'Spieler' without context usually means football player in Germany."},
{type:"teach",trg:"die Spielerin",src:"the player (female)",pos:"noun",gender:"f",note:"Feminine noun. Spieler + '-in.'\nThe German women's football team has won two World Cups.",example:"A: Die Spielerin ist sehr schnell.\nB: Ja, sie ist die beste Spielerin im Team.\nA: Seit wann spielt sie?\nB: Seit sie f\u00fcnf Jahre alt war.",exampleSrc:"A: The player is very fast.\nB: Yes, she's the best player on the team.\nA: How long has she been playing?\nB: Since she was five years old.",funFact:"The German women's national football team has won two World Cups. Spielerinnen are national heroes."},
{type:"teach",trg:"der Sportler",src:"the athlete (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'Sport' + '-ler.'\nGermany has won over 1,800 Olympic medals.",example:"A: Er ist ein guter Sportler.\nB: Ja, er l\u00e4uft jeden Tag zehn Kilometer.\nA: Ein echter Sportler.\nB: Sport ist sein Leben.",exampleSrc:"A: He's a good athlete.\nB: Yes, he runs ten kilometers every day.\nA: A true athlete.\nB: Sports is his life.",funFact:"Germany has won over 1,800 Olympic medals. Sportler are respected in every German community."},
{type:"teach",trg:"die Sportlerin",src:"the athlete (female)",pos:"noun",gender:"f",note:"Feminine noun. Sportler + '-in.'\nThe -ler/-lerin pattern is reliable as clockwork.",example:"A: Sie ist eine ber\u00fchmte Sportlerin.\nB: In welcher Sportart?\nA: Leichtathletik. Sie l\u00e4uft die 100 Meter.\nB: Eine fantastische Sportlerin!",exampleSrc:"A: She is a famous athlete.\nB: In which sport?\nA: Track and field. She runs the 100 meters.\nB: A fantastic athlete!",funFact:"The -ler/-lerin pattern works like clockwork. Sportler/Sportlerin, K\u00fcnstler/K\u00fcnstlerin. You can predict every profession pair."},
{type:"teach",trg:"die Sportart",src:"the type of sport",pos:"noun",gender:"f",note:"Feminine noun. Sport + Art (type/kind).\n'Welche Sportart machst du?'",example:"A: Welche Sportart magst du?\nB: Fu\u00dfball ist meine liebste Sportart.\nA: In Deutschland die popul\u00e4rste Sportart?\nB: Ja, Fu\u00dfball ist Nummer eins.",exampleSrc:"A: Which sport do you like?\nB: Football is my favorite sport.\nA: The most popular sport in Germany?\nB: Yes, football is number one.",funFact:"Sport + Art (type/kind). The compound is transparent: Art tells you it is a category. 'Welche Sportart machst du?' is the standard question."},
{type:"match",pairs:[{trg:"die Spielerin",src:"the player (female)"},{trg:"der Sportler",src:"the athlete (male)"},{trg:"die Sportlerin",src:"the athlete (female)"},{trg:"die Sportart",src:"the type of sport"}]},
{type:"teach",trg:"der Trainer",src:"the coach (male)",pos:"noun",gender:"m",note:"Masculine noun. From English 'trainer.'\nIn Germany, Trainer means coach, not shoes. Pronounced 'TRAY-ner.'",example:"A: Wer ist der Trainer?\nB: Der Mann mit dem Trainingsanzug.\nA: Er sieht streng aus.\nB: Gute Trainer sind immer ein bisschen streng.",exampleSrc:"A: Who is the coach?\nB: The man in the tracksuit.\nA: He looks strict.\nB: Good coaches are always a bit strict.",funFact:"In Germany, Trainer usually means coach, not shoes. A Fu\u00dfballtrainer coaches the team. Pronounced 'TRAY-ner,' not like English."},
{type:"fb",s:"Der {1} hat ein Tor geschossen! Nummer 9 ist der beste im Team.",a:["Spieler"],opts:["Spieler","Trainer","Sportler","Sieger"],hint:"Which masculine noun describes an active participant in a sport or game? It follows the standard -er agent noun pattern.",sSrc:"The player scored a goal! Number 9 is the best on the team."}
]},
{id:"deu_r17l5b",title:"Warum? Wozu? Stattdessen! (Teil 2)",icon:"\uD83D\uDCA1",xp:15,board:true,steps:[
{type:"intro",title:"Warum? Wozu? Stattdessen! (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Trainerin",src:"the coach (female)",pos:"noun",gender:"f",note:"Feminine noun. Trainer + '-in.'\nMore and more women coach professional teams in Germany.",example:"A: Die Trainerin ist sehr gut.\nB: Ja, unter ihrer Leitung gewinnt das Team.\nA: Seit wann ist sie Trainerin?\nB: Seit f\u00fcnf Jahren. Vorher war sie Spielerin.",exampleSrc:"A: The coach is very good.\nB: Yes, under her leadership the team wins.\nA: How long has she been a coach?\nB: For five years. Before that she was a player.",funFact:"More and more women coach professional teams in Germany. The language, as always, had the word ready."},
{type:"teach",trg:"der Spielplatz",src:"the playground",pos:"noun",gender:"m",note:"COMPOUND: Spiel (play) + Platz (place).\nMasculine noun. Spiel (play) + Platz (place).\nGerman playgrounds are more adventurous than American ones.",example:"A: Gibt es hier einen Spielplatz?\nB: Ja, gleich um die Ecke.\nA: Der Spielplatz sieht toll aus!\nB: Deutsche Spielpl\u00e4tze sind abenteuerlich.",exampleSrc:"A: Is there a playground here?\nB: Yes, just around the corner.\nA: The playground looks great!\nB: German playgrounds are adventurous.",funFact:"German playgrounds are famous for being more adventurous: higher climbing structures, fewer safety nets. Germans believe children learn by taking risks."},
{type:"teach",trg:"das Spielzeug",src:"the toy, the toys",pos:"noun",gender:"n",note:"Neuter noun. Spiel (play) + Zeug (stuff/thing).\nSame pattern as Flugzeug (airplane), Werkzeug (tool).",example:"A: Was f\u00fcr Spielzeug haben deutsche Kinder?\nB: Lego, Playmobil, Holzspielzeug.\nA: Playmobil ist deutsch?\nB: Ja! Aus F\u00fcrth in Bayern.",exampleSrc:"A: What kind of toys do German children have?\nB: Lego, Playmobil, wooden toys.\nA: Playmobil is German?\nB: Yes! From F\u00fcrth in Bavaria.",funFact:"Same pattern as Flugzeug (flight-thing = airplane), Werkzeug (work-thing = tool). German loves describing things by function + Zeug."},
{type:"teach",trg:"das Stadion",src:"the stadium",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'stadion.'\nGerman Stadien (plural) are some of the best-attended in the world.",example:"A: Das Stadion ist riesig!\nB: \u00dcber 80.000 Pl\u00e4tze.\nA: Deutsche Stadien sind immer voll.\nB: Fu\u00dfball ist hier Religion.",exampleSrc:"A: The stadium is enormous!\nB: Over 80,000 seats.\nA: German stadiums are always full.\nB: Football is religion here.",funFact:"Germany hosted the 2006 World Cup. German Stadien (plural) are some of the best-attended in the world."},
{type:"teach",trg:"das Golf",src:"golf (the sport)",pos:"noun",gender:"n",note:"Neuter noun for the sport. Der Golf is the Volkswagen car.\nSame spelling, different gender, completely different meaning.",example:"A: Spielst du Golf?\nB: Ja, aber nicht so oft.\nA: Golf oder Volkswagen Golf?\nB: Den Sport! Den VW Golf fahre ich auch.",exampleSrc:"A: Do you play golf?\nB: Yes, but not so often.\nA: Golf or Volkswagen Golf?\nB: The sport! I also drive the VW Golf.",funFact:"Das Golf is the sport. Der Golf is the Volkswagen car. Same spelling, different gender, completely different meaning."},
{type:"teach",trg:"der Ski",src:"the ski",pos:"noun",gender:"m",note:"Masculine noun. From Norwegian 'ski.'\nPronounced 'shee' in German. 'Ski fahren' = to ski.",example:"A: F\u00e4hrst du Ski?\nB: Ja, jeden Winter in den Alpen.\nA: Ski fahren ist toll!\nB: Die besten Pisten sind in \u00d6sterreich.",exampleSrc:"A: Do you ski?\nB: Yes, every winter in the Alps.\nA: Skiing is great!\nB: The best slopes are in Austria.",funFact:"Pronounced 'shee' in German, from Norwegian. The Alps make Germany, Austria, and Switzerland a Ski paradise. 'Ski fahren' uses 'fahren' (to drive/travel)."},
{type:"teach",trg:"die Gymnastik",src:"gymnastics",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'gymnastike.'\nFriedrich Ludwig Jahn invented the parallel bars, rings, and horse.",example:"A: Machst du Gymnastik?\nB: Ja, jeden Morgen.\nA: Gymnastik h\u00e4lt fit.\nB: Die Deutschen lieben Turnvereine.",exampleSrc:"A: Do you do gymnastics?\nB: Yes, every morning.\nA: Gymnastics keeps you fit.\nB: Germans love gymnastics clubs.",funFact:"Friedrich Ludwig Jahn, the 'father of gymnastics,' was German. He invented the parallel bars, rings, and horse. Turnvereine exist in every German town."},
{type:"teach",trg:"der Start",src:"the start",pos:"noun",gender:"m",note:"Masculine noun. Same as English.\n'Am Start' (at the start). Used for races, competitions, beginnings.",example:"A: Bist du bereit f\u00fcr den Start?\nB: Ja, ich stehe am Start.\nA: Auf die Pl\u00e4tze, fertig, los!\nB: Der Start war perfekt!",exampleSrc:"A: Are you ready for the start?\nB: Yes, I'm at the start.\nA: On your marks, get set, go!\nB: The start was perfect!",funFact:"Same as English. 'Startschuss' (starting shot) signals the beginning. Borrowed into German and used for races, competitions, and beginnings."},
{type:"teach",trg:"der Rekord",src:"the record (competitive)",pos:"noun",gender:"m",note:"Masculine noun. From English 'record.'\nNote: Rekord only means a competitive record, NOT a music record.",example:"A: Das ist ein neuer Rekord!\nB: Wirklich? Wie schnell?\nA: Unter zehn Sekunden!\nB: Einen Rekord zu brechen ist ein tolles Gef\u00fchl.",exampleSrc:"A: That's a new record!\nB: Really? How fast?\nA: Under ten seconds!\nB: Breaking a record is a great feeling.",funFact:"From English 'record.' Rekord only means a competitive record, NOT a music record (that is 'Platte' or 'Schallplatte')."},
{type:"teach",trg:"der Sieg",src:"the victory",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'sigu.'\n'Siegfried' (victory-peace) is one of Germany's most famous names.",example:"A: Was f\u00fcr ein Sieg!\nB: Ja, das Team hat gewonnen!\nA: Ein verdienter Sieg.\nB: Die Freude \u00fcber den Sieg ist riesig.",exampleSrc:"A: What a victory!\nB: Yes, the team won!\nA: A well-deserved victory.\nB: The joy about the victory is enormous.",funFact:"'Siegfried' (victory-peace) is one of Germany's most famous names. The Siegess\u00e4ule (Victory Column) stands in the heart of Berlin."},
{type:"teach",trg:"der Sieger",src:"the winner, the victor",pos:"noun",gender:"m",note:"Masculine noun. Sieg + '-er.'\n'Und der Sieger ist...' (And the winner is...).",example:"A: Und der Sieger ist...\nB: Wer? Wer hat gewonnen?\nA: Das Team in Rot!\nB: Ein verdienter Sieger!",exampleSrc:"A: And the winner is...\nB: Who? Who won?\nA: The team in red!\nB: A deserved winner!",funFact:"'Und der Sieger ist...' (And the winner is...). Every Karneval float competition has a Sieger. Every competition needs one."},
{type:"teach",trg:"die Siegerin",src:"the winner (female)",pos:"noun",gender:"f",note:"Feminine noun. Sieger + '-in.'\nBy now you can predict every profession pair in German.",example:"A: Die Siegerin bekommt den Pokal.\nB: Sie hat es verdient!\nA: Die beste Sportlerin des Turniers.\nB: Eine w\u00fcrdige Siegerin.",exampleSrc:"A: The winner receives the trophy.\nB: She deserved it!\nA: The best athlete of the tournament.\nB: A worthy winner.",funFact:"By now you can predict every profession pair in German. Sieger/Siegerin follows the same pattern as all the others."},
{type:"teach",trg:"siegen",src:"to win, to be victorious",pos:"verb",gender:null,note:"Regular verb. From Sieg.\n'Wer siegt, feiert' (Whoever wins, celebrates).",example:"A: Wer wird siegen?\nB: Ich hoffe, unsere Mannschaft.\nA: Siegen ist nicht alles.\nB: Aber es hilft!",exampleSrc:"A: Who will win?\nB: I hope our team.\nA: Winning isn't everything.\nB: But it helps!",funFact:"Related to 'besiegen' (to defeat) with the be- prefix adding a direct object. 'Wer siegt, feiert.'"},
{type:"teach",trg:"starten",src:"to start, to launch",pos:"verb",gender:null,note:"Regular verb. From English 'start.'\nSame word, same meaning, fully adopted into German grammar.",example:"A: Wann startet das Rennen?\nB: In f\u00fcnf Minuten.\nA: Alle Sportler starten gleichzeitig.\nB: M\u00f6ge der Beste siegen!",exampleSrc:"A: When does the race start?\nB: In five minutes.\nA: All athletes start at the same time.\nB: May the best one win!",funFact:"Same word, same meaning, fully adopted into German grammar. 'Das Rennen startet um 10 Uhr.'"},
{type:"tip",title:"Four Infinitive Constructions",text:"1. um...zu = in order to (purpose, same subject):\n'Ich trainiere, um zu siegen.' (I train in order to win.)\n\n2. ohne...zu = without doing (same subject):\n'Er feiert, ohne m\u00fcde zu werden.' (He celebrates without getting tired.)\n\n3. (an)statt...zu = instead of doing (same subject):\n'Statt zu arbeiten, feiert sie Karneval.' (Instead of working, she celebrates carnival.)\n\n4. damit = so that (DIFFERENT subjects):\n'Ich winke, damit die Leute Bonbons werfen.' (I wave so that the people throw candy.)\n\nKey rule: when both parts share the same subject, use um...zu. When the subjects differ, damit + conjugated verb is required.",deepDive:{title:"Word Order in Infinitive Clauses",text:"In all infinitive clauses, zu + infinitive goes to the end:\n\num ... zu feiern\nohne ... zu warten\nstatt ... zu arbeiten\n\nWith separable verbs, zu slides into the middle:\num anzufangen (not: um zu anfangen)\nohne aufzuh\u00f6ren (not: ohne zu aufh\u00f6ren)\nstatt mitzumachen (not: statt zu mitmachen)\n\nDamit-clauses have a conjugated verb at the END:\nIch singe, damit alle mitsingen.\n(The verb 'mitsingen' is conjugated)"}},
{type:"verb_table",title:"Infinitivklauseln im Vergleich",note:"Same subject = um/ohne/statt + zu + Infinitiv. Different subjects = damit + conjugated verb.",groups:[{label:"Gleiches Subjekt (Infinitivsatz)",rows:[{pronoun:"um...zu",form:"Ich lerne, um Deutsch zu sprechen.",src:"I learn in order to speak German."},{pronoun:"ohne...zu",form:"Er tanzt, ohne m\u00fcde zu werden.",src:"He dances without getting tired."},{pronoun:"(an)statt...zu",form:"Statt zu lernen, feiert sie.",src:"Instead of studying, she celebrates."}]},{label:"Verschiedene Subjekte (damit-Satz)",rows:[{pronoun:"damit",form:"Ich winke, damit du mich siehst.",src:"I wave so that you see me."}]}]},
{type:"tip",title:"Verbs with zu + Infinitive",text:"Some verbs take zu plus an infinitive directly, without um, ohne, or statt.\n\n- versuchen: Ich versuche, Deutsch zu sprechen.\n- anfangen: Er fängt an, Deutsch zu lernen.\n- aufhören: Sie hört auf zu rauchen.\n- vergessen: Ich habe vergessen, dich anzurufen.\n- beginnen: Es beginnt zu regnen.\n- planen: Wir planen, nach Köln zu fahren.\n- hoffen: Ich hoffe, dich bald zu sehen.\n\nThe conjugated verb comes in its normal position, then zu plus the infinitive close the clause.\n\nSpecial case: brauchen with nur or nicht replaces müssen in negations.\n'Du brauchst nicht zu kommen.' (You do not need to come.)",deepDive:{title:"Separable and Inseparable Verbs with zu",text:"Separable verbs: zu goes BETWEEN prefix and verb.\naufstehen: aufzustehen (not: zu aufstehen)\neinkaufen: einzukaufen\nmitmachen: mitzumachen\nkennenlernen: kennenzulernen\nfernsehen: fernzusehen\n\nInseparable verbs: zu goes BEFORE the whole verb.\nverstehen: zu verstehen\nbesuchen: zu besuchen\nentdecken: zu entdecken\n\nSeparable prefixes: auf, an, ein, mit, aus, ab, zu, vor\nInseparable prefixes: be-, ge-, er-, ver-, zer-, ent-, emp-, miss-"}},
{type:"mc",q:"Ich kaufe Bonbons, ___ die Kinder sich freuen.",opts:["damit","um...zu","ohne...zu","statt...zu"],ans:"damit",hint:"Who buys the candy? Who gets happy? When the two actions have different doers, which connector do you need?"},
{type:"mc",q:"'Er feiert die ganze Nacht, ohne m\u00fcde zu werden.' Was bedeutet 'ohne...zu'?",opts:["so that","without doing","instead of","in order to"],ans:"without doing",hint:"He celebrates all night, yet something expected never occurs. Which phrase captures an action that does NOT take place?"},
{type:"fb",s:"Mia tanzt, {1} aufzuh\u00f6ren.",a:["ohne"],opts:["ohne","um","statt","damit"],hint:"Mia keeps dancing and the stopping never happens. Which connector introduces an action that does not occur?",sSrc:"Mia dances without stopping."},
{type:"mc",q:"'Statt zu arbeiten, gehen wir zum Karneval.' Was machen wir?",opts:["Wir arbeiten und gehen dann zum Karneval","Wir arbeiten beim Karneval","Wir gehen zum Karneval statt zu arbeiten","Wir gehen ohne zu arbeiten"],ans:"Wir gehen zum Karneval statt zu arbeiten",hint:"Working is the option they skip. Going to carnival replaces it. Which connector introduces the skipped alternative?"},
{type:"fb",s:"Verumius zieht eine Toga an, {1} ein Senator zu sein.",a:["um"],opts:["um","ohne","statt","damit"],hint:"He puts on the toga for a PURPOSE: to be a senator.",sSrc:"Verumius puts on a toga in order to be a senator."},
{type:"drag_fill",s:"{1} nur zuzuschauen, tanzt Verumius mit, {2} Spa\u00df zu haben.",blanks:{"1":"Statt","2":"um"},pool:["Statt","um","ohne","damit","weil"],hint:"First: he does not just watch (alternative). Second: the purpose is to have fun.",sSrc:"Instead of just watching, Verumius dances along in order to have fun."},
{type:"mc",q:"'Ich singe, ___ alle mitmachen.' Welches Wort fehlt?",opts:["ohne","statt (nein)","um","damit"],ans:"damit",hint:"Who sings? Who joins in? When the subject of the second action is different from the first, which connector is required?"},
{type:"mc",q:"Was bedeutet 'der Spielplatz'?",opts:["the playground","the winner (female)","the winner, the victor","the coach (male)"],ans:"the playground",hint:"Spiel (play/game) + Platz (place/square). An outdoor area where children play."},
{type:"fb",s:"Wie sagt man 'the toy, the toys' auf Deutsch? {1}",a:["das Spielzeug"],opts:["das Spielzeug","die Sportart","der Spielplatz","der Sieger"],hint:"Spiel (play) + Zeug (stuff/things). Objects children use for playing.",sSrc:"How do you say 'the toy, the toys' in German?"},
{type:"mc",q:"Was bedeutet 'das Stadion'?",opts:["the record (competitive)","the stadium","to win, to be victorious","the player (female)"],ans:"the stadium",hint:"Greek/Latin cognate. A large sports venue for matches and competitions."},
{type:"fb",s:"Wie sagt man 'golf (the sport)' auf Deutsch? {1}",a:["das Golf"],opts:["das Golf","die Sportlerin","der Rekord","der Sieg"],hint:"An English/Scottish loanword. The sport with clubs, holes, and a small white ball.",sSrc:"How do you say 'golf (the sport)' in German?"},
{type:"mc",q:"Was bedeutet 'der Ski'?",opts:["the record (competitive)","the toy, the toys","the ski","the start"],ans:"the ski",hint:"Norwegian loanword. Long narrow boards strapped to boots for gliding on snow."},
{type:"fb",s:"Wie sagt man 'gymnastics' auf Deutsch? {1}",a:["die Gymnastik"],opts:["der Rekord","der Spieler","starten","die Gymnastik"],hint:"Greek cognate from 'gymnazein' (to exercise). Acrobatic floor and apparatus sport.",sSrc:"How do you say 'gymnastics' in German?"},
{type:"mc",q:"Was bedeutet 'der Start'?",opts:["the ski","the coach (female)","golf (the sport)","the start"],ans:"the start",hint:"Sounds like its English equivalent. The signal that a race begins. The gun fires and everyone runs."}
]},

// ─── Lesson 5: Kneipentour durch die Altstadt ─────────────────
{id:"deu_r17l6",title:"Kneipentour durch die Altstadt",icon:"\uD83C\uDF7A",xp:15,board:true,steps:[
{type:"intro",title:"Kneipentour durch die Altstadt",desc:"Mia leads Verumius through the Cologne old town. Every pub has a different program. Learn media and entertainment vocabulary and practice all four infinitive constructions.",goals:["Learn words for media, journalism, and entertainment","Practice all four infinitive constructions in conversation","Experience the Cologne pub tour with Mia"]},
{type:"teach",trg:"die Runde",src:"the round",pos:"noun",gender:"f",note:"Feminine noun. From 'rund' (round).\n'Eine Runde ausgeben' means to buy a round of drinks.",example:"A: Ich gebe eine Runde aus!\nB: F\u00fcr alle? Das ist gro\u00dfz\u00fcgig!\nA: Beim Karneval gibt man gerne Runden aus.\nB: Prost! K\u00f6lle Alaaf!",exampleSrc:"A: I'm buying a round!\nB: For everyone? That's generous!\nA: At carnival people gladly buy rounds.\nB: Cheers! K\u00f6lle Alaaf!",funFact:"'Eine Runde ausgeben' means to buy a round of drinks. At Karneval, rounds flow freely. A Runde through the Altstadt means visiting a circle of pubs."},
{type:"teach",trg:"die Unterhaltung",src:"the entertainment, the conversation",pos:"noun",gender:"f",note:"Feminine noun. Unter- (under/between) + Haltung (holding).\nCovers both entertainment and conversation. Context decides.",example:"A: Die Unterhaltung heute Abend war toll.\nB: Meinst du die Musik oder das Gespr\u00e4ch?\nA: Beides! Die ganze Unterhaltung.\nB: Karneval ist die beste Unterhaltung.",exampleSrc:"A: The entertainment tonight was great.\nB: Do you mean the music or the conversation?\nA: Both! The whole entertainment.\nB: Carnival is the best entertainment.",funFact:"Literally 'holding between' people. Covers both entertainment and conversation. Context decides which meaning applies."},
{type:"teach",trg:"das Vergn\u00fcgen",src:"the pleasure, the fun",pos:"noun",gender:"n",note:"Neuter noun. 'Es war mir ein Vergn\u00fcgen' (It was a pleasure).\n'Vergn\u00fcgungspark' = amusement park.",example:"A: Es war mir ein Vergn\u00fcgen!\nB: Mir auch! Was f\u00fcr ein Abend.\nA: Karneval ist ein reines Vergn\u00fcgen.\nB: Vergn\u00fcgen pur!",exampleSrc:"A: It was a pleasure!\nB: For me too! What an evening.\nA: Carnival is pure pleasure.\nB: Pure fun!",funFact:"'Es war mir ein Vergn\u00fcgen' (It was a pleasure). 'Vergn\u00fcgungspark' (amusement park) comes from the same root."},
{type:"teach",trg:"die Neuigkeit",src:"the news, the novelty",pos:"noun",gender:"f",note:"Feminine noun. Neu (new) + '-igkeit' (noun suffix).\nAlways feminine because of the -keit/-igkeit ending.",example:"A: Hast du Neuigkeiten?\nB: Ja! Morgen ist der Rosenmontagszug!\nA: Das ist keine Neuigkeit, das wissen alle!\nB: Aber es f\u00fchlt sich jedes Mal neu an.",exampleSrc:"A: Do you have any news?\nB: Yes! Tomorrow is the Rose Monday parade!\nA: That's not news, everyone knows that!\nB: But it feels new every time.",funFact:"'Hast du Neuigkeiten?' (Do you have news?). Always feminine because of the -keit/-igkeit ending. Always."},
{type:"teach",trg:"die Diskothek",src:"the disco, the nightclub",pos:"noun",gender:"f",note:"Feminine noun. From Greek 'diskos' + 'theke.'\nUsually shortened to 'Disko.'",example:"A: Gehen wir in die Diskothek?\nB: Klar! Welche Disko ist gut?\nA: Die mit der Karnevalsparty.\nB: In der Karnevalswoche hat jede Disko eine Party.",exampleSrc:"A: Shall we go to the disco?\nB: Sure! Which disco is good?\nA: The one with the carnival party.\nB: During carnival week every disco has a party.",funFact:"Usually shortened to 'Disko.' During Karneval, every Disko runs themed carnival parties. The word sounds retro, but the parties are modern."},
{type:"match",pairs:[{trg:"die Unterhaltung",src:"the entertainment, the conversation"},{trg:"das Vergn\u00fcgen",src:"the pleasure, the fun"},{trg:"die Neuigkeit",src:"the news, the novelty"},{trg:"die Diskothek",src:"the disco, the nightclub"}]},
{type:"teach",trg:"die Galerie",src:"the gallery",pos:"noun",gender:"f",note:"Feminine noun. From Italian 'galleria.'\nCologne has over 30 Galerien in the city center.",example:"A: Gibt es hier eine Galerie?\nB: Ja, sogar die Galerien machen beim Karneval mit.\nA: Kunst und Karneval passen zusammen?\nB: In K\u00f6ln passt alles zusammen.",exampleSrc:"A: Is there a gallery here?\nB: Yes, even the galleries participate in carnival.\nA: Art and carnival go together?\nB: In Cologne everything goes together.",funFact:"Even art galleries participate in Karneval with themed exhibitions. Cologne has over 30 Galerien in the city center alone."},
{type:"fb",s:"Karneval ist die beste {1}. Musik, Tanz und Lachen den ganzen Abend.",a:["Unterhaltung"],opts:["Unterhaltung","Diskothek","Galerie","Runde"],hint:"Which feminine noun covers both a fun activity AND an exchange of words? It literally means something that holds your attention.",sSrc:"Carnival is the best entertainment. Music, dance, and laughter all evening."},
{type:"mc",q:"Es war ein sch\u00f6ner Abend. Was sagt man h\u00f6flich zum Abschied?",opts:["Das war ein Vergn\u00fcgen!","Das war eine Diskothek!","Das war eine Neuigkeit!","Das war eine Serie!"],ans:"Das war ein Vergn\u00fcgen!",hint:"Which neuter noun means pleasure or fun, used in formal farewells?"},
{type:"teach",trg:"die Serie",src:"the series (TV)",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'series.'\nNetflix Germany produces Serien like 'Dark' and 'Babylon Berlin.'",example:"A: Schaust du eine gute Serie?\nB: Ja, eine deutsche Serie auf Netflix.\nA: Welche?\nB: 'Dark.' Die ist wahnsinnig gut.",exampleSrc:"A: Are you watching a good series?\nB: Yes, a German series on Netflix.\nA: Which one?\nB: 'Dark.' It's insanely good.",funFact:"Netflix Germany produces German-language Serien like 'Dark' and 'Babylon Berlin.' Germans binge-watch Serien just like everyone else."},
{type:"teach",trg:"die Reportage",src:"the report, the feature story",pos:"noun",gender:"f",note:"Feminine noun. From French 'reportage.'\nGerman TV sends Reportage teams to cover Karneval every year.",example:"A: Hast du die Reportage \u00fcber Karneval gesehen?\nB: Ja, im Fernsehen. Sehr gut gemacht.\nA: Die Reportage hat alles gezeigt.\nB: Von den Kost\u00fcmen bis zum Rosenmontagszug.",exampleSrc:"A: Did you see the report about carnival?\nB: Yes, on TV. Very well done.\nA: The report showed everything.\nB: From the costumes to the Rose Monday parade.",funFact:"German TV sends Reportage teams to cover Karneval every year. It is prime-time content across the country."},
{type:"teach",trg:"der Reporter",src:"the reporter (male)",pos:"noun",gender:"m",note:"Masculine noun. Same as English.\nDuring Karneval, Reporter interview costumed people in the crowd.",example:"A: Schau, ein Reporter!\nB: Er interviewt die Leute in Kost\u00fcmen.\nA: Reporter m\u00fcssen beim Karneval Bonbons ausweichen.\nB: Ein gef\u00e4hrlicher Job!",exampleSrc:"A: Look, a reporter!\nB: He's interviewing people in costumes.\nA: Reporters have to dodge candy at carnival.\nB: A dangerous job!",funFact:"During Karneval, Reporter stand in the crowd interviewing costumed people. The best interviews become viral clips. Reporter must dodge flying candy."},
{type:"teach",trg:"die Reporterin",src:"the reporter (female)",pos:"noun",gender:"f",note:"Feminine noun. Reporter + '-in.'\nThe pattern never fails.",example:"A: Die Reporterin ist live vor Ort.\nB: Sie berichtet direkt vom Rosenmontagszug.\nA: Ein toller Job!\nB: Reporterin beim Karneval, Traumberuf!",exampleSrc:"A: The reporter is live on the scene.\nB: She's reporting directly from the Rose Monday parade.\nA: A great job!\nB: Being a reporter at carnival, dream job!",funFact:"The -er/-erin pattern never fails. At this point you could build feminine forms in your sleep."},
{type:"teach",trg:"der Journalist",src:"the journalist (male)",pos:"noun",gender:"m",note:"Masculine noun. From French 'journaliste.'\nA broader term than Reporter.",example:"A: Bist du Journalist?\nB: Ja, ich schreibe f\u00fcr eine Zeitung.\nA: \u00dcber den Karneval?\nB: Ja, Karneval ist immer eine gute Geschichte.",exampleSrc:"A: Are you a journalist?\nB: Yes, I write for a newspaper.\nA: About the carnival?\nB: Yes, carnival is always a good story.",funFact:"A broader term than Reporter. Journalisten write, broadcast, and analyze. Karneval political satire gives Journalisten plenty of material."},
{type:"mc",q:"Eine Fernsehsendung \u00fcber den Karneval, mit Interviews und Bildern. Das ist eine...",opts:["Reportage","Serie","Diskothek (nein)","Galerie"],ans:"Reportage",hint:"A journalistic feature story with footage and interviews, from French."}
]},
{id:"deu_r17l6b",title:"Kneipentour durch die Altstadt (Teil 2)",icon:"\uD83C\uDF7A",xp:15,board:true,steps:[
{type:"intro",title:"Kneipentour durch die Altstadt (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"fb",s:"Wir geben eine {1} aus. Prost, K\u00f6lle Alaaf!",a:["Runde"],opts:["Runde","Unterhaltung","Neuigkeit","Galerie"],hint:"Which feminine noun means a round of drinks? From 'rund' (round).",sSrc:"We are buying a round. Cheers, K\u00f6lle Alaaf!"},
{type:"teach",trg:"die Journalistin",src:"the journalist (female)",pos:"noun",gender:"f",note:"Feminine noun. Journalist + '-in.'\nGermany has more women in journalism than most European countries.",example:"A: Die Journalistin schreibt einen Artikel.\nB: \u00dcber die Karnevalstradition.\nA: Sie kennt sich sehr gut aus.\nB: Eine erfahrene Journalistin.",exampleSrc:"A: The journalist is writing an article.\nB: About the carnival tradition.\nA: She knows a lot about it.\nB: An experienced journalist.",funFact:"Germany has more women in journalism than most European countries. The language keeps up with -in."},
{type:"teach",trg:"der Fotograf",src:"the photographer (male)",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'photos' (light) + 'graphein' (to write).\nLiterally 'light writer.'",example:"A: Der Fotograf macht Bilder vom Umzug.\nB: Karneval ist ein Traum f\u00fcr Fotografen.\nA: Farbe, Bewegung, Emotion.\nB: Jedes Foto erz\u00e4hlt eine Geschichte.",exampleSrc:"A: The photographer takes pictures of the parade.\nB: Carnival is a dream for photographers.\nA: Color, movement, emotion.\nB: Every photo tells a story.",funFact:"From Greek: 'light writer.' Karneval is a Fotograf's dream: color, movement, emotion, chaos. Every shot tells a story."},
{type:"teach",trg:"die Fotografie",src:"the photography, the photograph",pos:"noun",gender:"f",note:"Feminine noun. The -ie ending is always feminine.\nCovers both the art and the individual image.",example:"A: Die Fotografie ist wundersch\u00f6n!\nB: Danke! Fotografie ist meine Leidenschaft.\nA: Machst du beruflich Fotografie?\nB: Ja, besonders bei Events wie Karneval.",exampleSrc:"A: The photograph is beautiful!\nB: Thanks! Photography is my passion.\nA: Do you do photography professionally?\nB: Yes, especially at events like carnival.",funFact:"The -ie ending is always feminine. Fotografie as an art form was partly developed with German optics that made modern photography possible."},
{type:"teach",trg:"original",src:"original",pos:"adj",gender:null,note:"Same as English. 'Ein originales Kost\u00fcm' (an original costume).\nThe most admired Karneval costumes are original and handmade.",example:"A: Ist das Kost\u00fcm original?\nB: Ja, komplett selbst gemacht!\nA: Originale Kost\u00fcme sind die besten.\nB: Gekauft ist okay, aber original ist besser.",exampleSrc:"A: Is the costume original?\nB: Yes, completely self-made!\nA: Original costumes are the best.\nB: Store-bought is okay, but original is better.",funFact:"The most admired Karneval costumes are original: handmade, unique, creative. Store-bought is acceptable but not celebrated."},
{type:"teach",trg:"realistisch",src:"realistic",pos:"adj",gender:null,note:"From 'real' + '-istisch.'\nSome Karneval costumes are museum-quality realistic.",example:"A: Das Kost\u00fcm ist unglaublich realistisch!\nB: Man k\u00f6nnte denken, er ist wirklich ein Ritter.\nA: Manche Kost\u00fcme sind Kunstwerke.\nB: Realistisch und trotzdem lustig.",exampleSrc:"A: The costume is incredibly realistic!\nB: You'd think he's really a knight.\nA: Some costumes are works of art.\nB: Realistic and still funny.",funFact:"Some Karneval costumes are museum-quality. Others are intentionally unrealistisch. Both approaches work."},
{type:"match",pairs:[{trg:"der Fotograf",src:"the photographer (male)"},{trg:"die Fotografie",src:"the photography, the photograph"},{trg:"original",src:"original"},{trg:"realistisch",src:"realistic"}]},
{type:"teach",trg:"interkulturell",src:"intercultural",pos:"adj",gender:null,note:"Inter- (between) + kulturell (cultural).\nKarneval in Cologne is interkulturell: many influences blend.",example:"A: Karneval in K\u00f6ln ist sehr interkulturell.\nB: Ja, Menschen aus aller Welt feiern zusammen.\nA: T\u00fcrkische, italienische, japanische Einfl\u00fcsse.\nB: Das macht den K\u00f6lner Karneval besonders.",exampleSrc:"A: Carnival in Cologne is very intercultural.\nB: Yes, people from all over the world celebrate together.\nA: Turkish, Italian, Japanese influences.\nB: That's what makes Cologne carnival special.",funFact:"Karneval in Cologne blends Turkish, Italian, Japanese, and Brazilian influences with Rhineland traditions. Truly interkulturell."},
{type:"teach",trg:"auftreten",src:"to appear, to perform",pos:"verb",gender:null,note:"Separable verb. Auf (on) + treten (to step).\n'Die Band tritt heute auf' (The band performs today).",example:"A: Wann tritt die Band auf?\nB: In einer Stunde.\nA: Sie treten auf der gro\u00dfen B\u00fchne auf.\nB: Ich freue mich auf den Auftritt!",exampleSrc:"A: When does the band perform?\nB: In one hour.\nA: They're performing on the main stage.\nB: I'm looking forward to the performance!",funFact:"At Karneval, everyone tritt auf, whether on stage or in the street. The separable prefix auf- means 'up/onto.'"},
{type:"teach",trg:"begegnen",src:"to encounter, to meet (by chance)",pos:"verb",gender:null,note:"Uses sein as auxiliary, not haben.\nBegegnen implies chance, not planning.",example:"A: Ich bin ihr zuf\u00e4llig begegnet.\nB: Beim Karneval begegnet man vielen Menschen.\nA: Jede Begegnung ist eine \u00dcberraschung.\nB: Das macht den Karneval so besonders.",exampleSrc:"A: I ran into her by chance.\nB: At carnival you encounter many people.\nA: Every encounter is a surprise.\nB: That's what makes carnival so special.",funFact:"Uses sein as auxiliary: 'Ich bin ihr begegnet.' Begegnen implies chance, not planning. Karneval is full of zuf\u00e4llige Begegnungen."},
{type:"teach",trg:"sorgen",src:"to take care of, to ensure",pos:"verb",gender:null,note:"'F\u00fcr Stimmung sorgen' (to ensure a good atmosphere).\n'Sich Sorgen machen' = to worry. Different meanings.",example:"A: Wer sorgt f\u00fcr die Musik?\nB: Die Band sorgt f\u00fcr Stimmung.\nA: Mach dir keine Sorgen!\nB: Beim Karneval sorgt man nur f\u00fcr Spa\u00df.",exampleSrc:"A: Who takes care of the music?\nB: The band ensures a good atmosphere.\nA: Don't worry!\nB: At carnival you only take care of fun.",funFact:"'F\u00fcr Stimmung sorgen' = to ensure a good atmosphere. 'Sich Sorgen machen' = to worry. With and without 'sich,' completely different meanings."},
{type:"drag_fill",s:"Verumius tanzt, {1} ein guter T\u00e4nzer zu sein, {2} Spa\u00df zu haben.",blanks:{"1":"ohne","2":"um"},pool:["ohne","um","statt","damit","weil"],hint:"First blank: being a good dancer is an absent quality. Second blank: the reason he dances anyway.",sSrc:"Verumius dances without being a good dancer, in order to have fun."},
{type:"mc",q:"Was bedeutet 'die Journalistin'?",opts:["the journalist (female)","the round","the reporter (female)","the gallery"],ans:"the journalist (female)",hint:"French loanword with feminine -in ending. A woman who writes for newspapers or media."},
{type:"fb",s:"{1} macht Bilder vom Umzug.",a:["der Fotograf"],opts:["der Reporter","das Vergn\\u00fcgen","die Reporterin","der Fotograf"],hint:"Greek roots: photos (light) + graphein (to write). A person who captures images with a camera.",sSrc:"The photographer takes pictures of the parade."},
{type:"mc",q:"Was bedeutet 'die Fotografie'?",opts:["the round","the photography, the photograph","the entertainment, the conversation","intercultural"],ans:"the photography, the photograph",hint:"Greek: photos (light) + graphie (writing). The art or product of capturing images."},
{type:"fb",s:"Ist das Kost\\u00fcm {1}?",a:["original"],opts:["original","die Fotografie","die Runde","auftreten"],hint:"Latin cognate. Means authentic, genuine, not a copy. Same word in English and French.",sSrc:"Is the costume original?"},
{type:"mc",q:"Was bedeutet 'realistisch'?",opts:["to encounter, to meet (by chance)","the report, the feature story","realistic","the pleasure, the fun"],ans:"realistic",hint:"Latin cognate from 'realis'. True to life, reflecting things as they actually are."},
{type:"fb",s:"Karneval in K\\u00f6ln ist sehr {1}.",a:["interkulturell"],opts:["interkulturell","die Fotografie","realistisch","die Diskothek"],hint:"Inter- (between) + kulturell (cultural). Involving multiple cultures mixing together.",sSrc:"Carnival in Cologne is very intercultural."},
{type:"mc",q:"Was bedeutet 'auftreten'?",opts:["to take care of, to ensure","the news, the novelty","the reporter (female)","to appear, to perform"],ans:"to appear, to perform",hint:"Auf- (up/onto) + treten (to step). To step onto a stage and present yourself publicly."},
{type:"fb",s:"Wie sagt man 'to encounter, to meet (by chance)' auf Deutsch? {1}",a:["begegnen"],opts:["die Journalistin","die Neuigkeit","sorgen","begegnen"],hint:"Be- prefix + gegen (against/toward). To come face to face with someone unexpectedly.",sSrc:"How do you say 'to encounter, to meet (by chance)' in German?"},
{type:"mc",q:"Was bedeutet 'sorgen'?",opts:["to take care of, to ensure","the news, the novelty","to appear, to perform","the photography, the photograph"],ans:"to take care of, to ensure",hint:"From Sorge (worry). 'Sorgen für' = to look after someone. 'Sich sorgen' = to worry."}
]},

// ─── Lesson 6: Rosenmontagszug! ──────────────────────────────
{id:"deu_r17l7",title:"Rosenmontagszug!",icon:"\uD83C\uDF8A",xp:15,board:true,steps:[
{type:"intro",title:"Rosenmontagszug!",desc:"The climax of Carnival. Seven kilometers of organized chaos. Giant floats, flying candy, over a million people. Verumius experiences Germany's biggest street parade.",goals:["Experience the Rose Monday parade through Verumius' eyes","Learn vocabulary for spectators, talents, and extreme emotions","Master all four infinitive constructions in quiz contexts"]},
{type:"teach",trg:"der Zuschauer",src:"the spectator (male)",pos:"noun",gender:"m",note:"Masculine noun. Zu (to/at) + schauen (to watch) + '-er.'\nOver one million Zuschauer line the parade route.",example:"A: Wie viele Zuschauer sind hier?\nB: \u00dcber eine Million!\nA: Die Zuschauer stehen seit Stunden.\nB: F\u00fcr den Rosenmontagszug wartet man gerne.",exampleSrc:"A: How many spectators are here?\nB: Over one million!\nA: The spectators have been standing for hours.\nB: For the Rose Monday parade you gladly wait.",funFact:"Zu + schauen + -er: someone who watches (schaut zu). Over one million Zuschauer line the Rosenmontagszug route."},
{type:"teach",trg:"die Zuschauerin",src:"the spectator (female)",pos:"noun",gender:"f",note:"Feminine noun. Zuschauer + '-in.'\nThe -er/-erin pattern is now automatic for you.",example:"A: Die Zuschauerin neben mir ist begeistert.\nB: Alle Zuschauerinnen und Zuschauer feiern.\nA: Egal ob Mann oder Frau.\nB: Karneval macht alle gleich.",exampleSrc:"A: The spectator next to me is thrilled.\nB: All spectators are celebrating.\nA: Whether man or woman.\nB: Carnival makes everyone equal.",funFact:"The -er/-erin pattern is now automatic. You are building a profession vocabulary factory."},
{type:"teach",trg:"der Schauspieler",src:"the actor (male)",pos:"noun",gender:"m",note:"Masculine noun. Schau (show) + Spiel (play) + '-er.'\nLiterally 'show-player.'",example:"A: Ist er ein Schauspieler?\nB: Nein, er ist nur gut verkleidet!\nA: Er spielt seine Rolle perfekt.\nB: Beim Karneval ist jeder ein Schauspieler.",exampleSrc:"A: Is he an actor?\nB: No, he's just well disguised!\nA: He plays his role perfectly.\nB: At carnival everyone is an actor.",funFact:"Literally 'show-player.' German compound logic: someone who plays (spielt) in a show (Schau)."},
{type:"teach",trg:"die Schauspielerin",src:"the actor (female)",pos:"noun",gender:"f",note:"Feminine noun. Schauspieler + '-in.'\nAt Karneval, everyone is a Schauspielerin for a day.",example:"A: Die Schauspielerin tr\u00e4gt ein tolles Kost\u00fcm.\nB: Ist sie wirklich Schauspielerin?\nA: Ja, sie spielt im K\u00f6lner Theater.\nB: Kein Wunder, dass sie so gut ist!",exampleSrc:"A: The actress is wearing a great costume.\nB: Is she really an actress?\nA: Yes, she acts at the Cologne theater.\nB: No wonder she's so good!",funFact:"At Karneval, everyone is a Schauspielerin for a day. The costume is the role."},
{type:"teach",trg:"der Zuh\u00f6rer",src:"the listener (male)",pos:"noun",gender:"m",note:"Masculine noun. Zu (to) + h\u00f6ren (to hear/listen) + '-er.'\nSomeone who actively listens (h\u00f6rt zu).",example:"A: Die Zuh\u00f6rer singen alle mit!\nB: Bei Karnevalsmusik kann niemand still sein.\nA: Aus Zuh\u00f6rern werden S\u00e4nger.\nB: Das ist der Geist des Karnevals.",exampleSrc:"A: The listeners are all singing along!\nB: With carnival music nobody can stay quiet.\nA: Listeners become singers.\nB: That's the spirit of carnival.",funFact:"Radio has Zuh\u00f6rer, lectures have Zuh\u00f6rer, Karneval songs have Zuh\u00f6rer who become Mits\u00e4nger (people who sing along)."},
{type:"match",pairs:[{trg:"die Zuschauerin",src:"the spectator (female)"},{trg:"der Schauspieler",src:"the actor (male)"},{trg:"die Schauspielerin",src:"the actor (female)"},{trg:"der Zuh\u00f6rer",src:"the listener (male)"}]},
{type:"teach",trg:"die Zuh\u00f6rerin",src:"the listener (female)",pos:"noun",gender:"f",note:"Feminine noun. Zuh\u00f6rer + '-in.'\nThe zu- prefix means 'toward.' Zuh\u00f6rer listens toward something.",example:"A: Die Zuh\u00f6rerin klatscht begeistert.\nB: Sie kennt jedes Lied.\nA: Eine echte Karnevalsfan.\nB: Zuh\u00f6rerin und Mits\u00e4ngerin!",exampleSrc:"A: The listener claps enthusiastically.\nB: She knows every song.\nA: A true carnival fan.\nB: Listener and sing-along participant!",funFact:"German distinguishes what English does not: Zuh\u00f6rer listens actively (zu means toward), H\u00f6rer may hear more passively."},
{type:"fb",s:"Beim Karneval ist jeder ein {1}. Man spielt eine Rolle, auch ohne B\u00fchne.",a:["Schauspieler"],opts:["Schauspieler","Zuschauer","Zuh\u00f6rer","Sportler"],hint:"Which compound noun means 'actor,' literally a 'show-player'?",sSrc:"At carnival everyone is an actor. You play a role, even without a stage."},
{type:"mc",q:"Der Zuschauer schaut zu, die Zuschauerin schaut auch zu. Welches Muster bildet die weibliche Form?",opts:["Zuschauer + -in = Zuschauerin","Zuschauer + -erin = Zuschauerin","Zuschauer + -frau = Zuschauerfrau","Zuschau + -erin = Zuschauerin"],ans:"Zuschauer + -in = Zuschauerin",hint:"The standard German pattern for feminine profession forms adds a specific suffix to the masculine noun."},
{type:"teach",trg:"der H\u00f6rer",src:"the listener, the receiver",pos:"noun",gender:"m",note:"Masculine noun. H\u00f6ren (to hear) + '-er.'\nAlso means 'telephone receiver.'",example:"A: Wie viele H\u00f6rer hat der Radiosender?\nB: \u00dcber eine Million.\nA: H\u00f6rer und Zuschauer, das ist ein Unterschied.\nB: H\u00f6rer h\u00f6ren, Zuschauer schauen.",exampleSrc:"A: How many listeners does the radio station have?\nB: Over one million.\nA: Listeners and spectators, that's a difference.\nB: Listeners hear, spectators watch.",funFact:"Also means 'telephone receiver' (the part you hold to your ear). Broader than Zuh\u00f6rer (active listener)."},
{type:"teach",trg:"die H\u00f6rerin",src:"the listener (female)",pos:"noun",gender:"f",note:"Feminine noun. H\u00f6rer + '-in.'\nThe difference: H\u00f6rer hears passively, Zuh\u00f6rer listens actively.",example:"A: Die H\u00f6rerin ruft beim Radiosender an.\nB: Was m\u00f6chte sie?\nA: Ein Karnevalslied w\u00fcnschen.\nB: Radio und Karneval geh\u00f6ren zusammen.",exampleSrc:"A: The listener calls the radio station.\nB: What does she want?\nA: To request a carnival song.\nB: Radio and carnival belong together.",funFact:"H\u00f6rer may hear passively, Zuh\u00f6rer listens actively. German distinguishes what English often does not."},
{type:"teach",trg:"das Tor",src:"the gate, the goal",pos:"noun",gender:"n",note:"Neuter noun. 'Ein Tor schie\u00dfen' (to score a goal) in football.\nAlso 'gateway': das Brandenburger Tor.",example:"A: Tor! Ein Tor!\nB: Wer hat das Tor geschossen?\nA: Die Nummer 10!\nB: Was f\u00fcr ein fantastisches Tor!",exampleSrc:"A: Goal! A goal!\nB: Who scored the goal?\nA: Number 10!\nB: What a fantastic goal!",funFact:"'Ein Tor schie\u00dfen' = to score a goal. Also 'gateway': das Brandenburger Tor. During Karneval parades, city gates are symbolically opened."},
{type:"teach",trg:"das Talent",src:"the talent",pos:"noun",gender:"n",note:"Neuter noun. From Greek 'talanton.' Same word in English.\nKarneval discovers Talente: comedy, music, costume design.",example:"A: Sie hat ein echtes Talent!\nB: F\u00fcr was?\nA: F\u00fcr Kost\u00fcmdesign.\nB: Talent kommt beim Karneval zur Geltung.",exampleSrc:"A: She has a real talent!\nB: For what?\nA: For costume design.\nB: Talent shines at carnival.",funFact:"Karneval discovers Talente in comedy, music, and costume design. The B\u00fchne is open to everyone with Talent."},
{type:"teach",trg:"der Typ",src:"the type, the guy",pos:"noun",gender:"m",note:"Masculine noun. From Greek 'typos.'\nColloquially: 'der Typ' means 'that guy.'",example:"A: Wer ist der Typ da dr\u00fcben?\nB: Keine Ahnung, aber sein Kost\u00fcm ist klasse.\nA: Ein lustiger Typ.\nB: Beim Karneval trifft man alle Typen.",exampleSrc:"A: Who is that guy over there?\nB: No idea, but his costume is awesome.\nA: A funny guy.\nB: At carnival you meet all types.",funFact:"In colloquial German, 'der Typ' means 'that guy.' 'Er ist ein lustiger Typ' (He is a funny guy). Also means 'type' formally."},
{type:"mc",q:"Das Nebeneinander von H\u00f6rer und Zuh\u00f6rer zeigt einen Unterschied. Was h\u00f6rt ein Zuh\u00f6rer anders?",opts:["Er h\u00f6rt passiv","Er h\u00f6rt aktiv zu","Er h\u00f6rt nichts","Er h\u00f6rt Musik"],ans:"Er h\u00f6rt aktiv zu",hint:"The zu- prefix in Zuh\u00f6rer means 'toward.' This listener pays attention actively, not passively."}
]},
{id:"deu_r17l7b",title:"Rosenmontagszug! (Teil 2)",icon:"\uD83C\uDF8A",xp:15,board:true,steps:[
{type:"intro",title:"Rosenmontagszug! (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"fb",s:"\u00dcber eine Million {1} stehen am Stra\u00dfenrand und schauen den Rosenmontagszug.",a:["Zuschauer"],opts:["Zuschauer","Schauspieler","Zuh\u00f6rer","H\u00f6rer"],hint:"Which compound noun means 'spectators' who watch (schauen zu) an event?",sSrc:"Over one million spectators line the roadside and watch the Rose Monday parade."},
{type:"teach",trg:"das Ballett",src:"the ballet",pos:"noun",gender:"n",note:"Neuter noun. From Italian 'balletto' (little dance).\nThe Funkenmariechen performs moves from Ballett and military drill.",example:"A: Ist das Ballett?\nB: So \u00e4hnlich. Das ist eine Funkenmariechen.\nA: Eine Mischung aus Ballett und Milit\u00e4rtanz?\nB: Genau. Eine Jahrhunderte alte Tradition.",exampleSrc:"A: Is that ballet?\nB: Sort of. That's a Funkenmariechen.\nA: A mix of ballet and military dance?\nB: Exactly. A centuries-old tradition.",funFact:"The Funkenmariechen (carnival solo dancer) performs moves from Ballett and military drill. Cologne's dance tradition is centuries old."},
{type:"teach",trg:"wahnsinnig",src:"insane, incredibly",pos:"adj",gender:null,note:"Wahn (delusion) + Sinn (sense). Literally 'delusional-minded.'\nUsed as intensifier: 'wahnsinnig gut' (insanely good).",example:"A: Die Parade ist wahnsinnig laut!\nB: Wahnsinnig bunt, wahnsinnig lustig.\nA: Wahnsinnig viele Menschen.\nB: Einfach wahnsinnig!",exampleSrc:"A: The parade is insanely loud!\nB: Insanely colorful, insanely funny.\nA: An insane number of people.\nB: Simply insane!",funFact:"Wahn (delusion) + Sinn (sense). Used as an intensifier: 'wahnsinnig gut' (insanely good), 'wahnsinnig laut' (insanely loud). The Rosenmontagszug is wahnsinnig everything."},
{type:"teach",trg:"allerbest",src:"the very best of all",pos:"adj",gender:null,note:"Aller- (of all) + best (best). A double superlative.\n'Das allerbeste Kost\u00fcm!' Reserved for when 'best' is not enough.",example:"A: Das war der allerbeste Tag!\nB: Findest du? Besser als Berlin?\nA: Berlin ist toll, aber heute war allerbest.\nB: Karneval macht alles allerbest.",exampleSrc:"A: That was the very best day!\nB: You think? Better than Berlin?\nA: Berlin is great, but today was the very best.\nB: Carnival makes everything the very best.",funFact:"Aller- cranks any superlative to maximum. 'Das allerbeste Kost\u00fcm!' Reserved for when 'best' is simply not enough."},
{type:"teach",trg:"allersch\u00f6nst",src:"the most beautiful of all",pos:"adj",gender:null,note:"Aller- + sch\u00f6nst. Same amplifier.\n'Der allersch\u00f6nste Tag' (The most beautiful day of all).",example:"A: Das ist der allersch\u00f6nste Wagen!\nB: Ja, die Farben sind unglaublich.\nA: Der allersch\u00f6nste Moment.\nB: Karneval liefert allersch\u00f6nste Erinnerungen.",exampleSrc:"A: That is the most beautiful float of all!\nB: Yes, the colors are incredible.\nA: The most beautiful moment of all.\nB: Carnival delivers the most beautiful memories.",funFact:"Same aller- amplifier. 'Der allersch\u00f6nste Tag.' Verumius might use this about Rosenmontag."},
{type:"teach",trg:"springen",src:"to jump",pos:"verb",gender:null,note:"Irregular: sprang, gesprungen. Same root as English 'spring.'\nChildren springen to catch candy from the air.",example:"A: Die Kinder springen nach den Bonbons!\nB: Alle springen und lachen.\nA: Ich springe auch!\nB: Spring h\u00f6her, dann f\u00e4ngst du mehr!",exampleSrc:"A: The children jump for the candy!\nB: Everyone jumps and laughs.\nA: I'm jumping too!\nB: Jump higher, then you'll catch more!",funFact:"Irregular: sprang, gesprungen. Same root as English 'spring.' At the parade, children springen to catch candy from the air."},
{type:"match",pairs:[{trg:"wahnsinnig",src:"insane, incredibly"},{trg:"allerbest",src:"the very best of all"},{trg:"allersch\u00f6nst",src:"the most beautiful of all"},{trg:"springen",src:"to jump"}]},
{type:"teach",trg:"rennen",src:"to run (fast)",pos:"verb",gender:null,note:"Irregular: rannte, gerannt. More urgent than 'laufen.'\n'Renn nicht!' (Don't run!).",example:"A: Die Kinder rennen den Bonbons hinterher!\nB: Renn nicht so schnell!\nA: Aber die Schokolade!\nB: Erwachsene rennen auch, wenn niemand hinschaut.",exampleSrc:"A: The children run after the candy!\nB: Don't run so fast!\nA: But the chocolate!\nB: Adults run too, when nobody's watching.",funFact:"More urgent than 'laufen.' Children rennen after candy at the parade. Adults pretend not to, then rennen when nobody watches."},
{type:"teach",trg:"klettern",src:"to climb",pos:"verb",gender:null,note:"Regular verb. 'Auf einen Baum klettern' (to climb a tree).\nAlso a popular sport: Kletterhalle (climbing gym).",example:"A: Die Kinder klettern auf die Absperrung!\nB: Um besser zu sehen.\nA: Vorsicht beim Klettern!\nB: Kinder klettern \u00fcberall.",exampleSrc:"A: The children climb on the barrier!\nB: In order to see better.\nA: Be careful climbing!\nB: Children climb everywhere.",funFact:"During Karneval, children klettern on barriers to get a better view. Klettern is also a popular sport: Kletterhalle (climbing gym)."},
{type:"teach",trg:"treiben",src:"to drive, to push, to do (sport)",pos:"verb",gender:null,note:"Irregular: trieb, getrieben. 'Sport treiben' (to do sports).\n'Was treibst du?' colloquially means 'What are you up to?'",example:"A: Was treibst du beim Karneval?\nB: Ich treibe mich durch die Altstadt!\nA: Sport treiben oder Spa\u00df treiben?\nB: Beim Karneval? Nur Spa\u00df!",exampleSrc:"A: What are you up to at carnival?\nB: I'm roaming through the Old Town!\nA: Doing sports or having fun?\nB: At carnival? Just fun!",funFact:"'Sport treiben' = to do sports. 'Was treibst du?' colloquially means 'What are you up to?' At Karneval, die Menge treibt durch die Stra\u00dfen."},
{type:"teach",trg:"treten",src:"to step, to kick",pos:"verb",gender:null,note:"Irregular: trat, getreten. Many separable compounds:\neintreten = enter, auftreten = perform, austreten = exit.",example:"A: Treten Sie bitte ein!\nB: Danke! Wo ist die B\u00fchne?\nA: Geradeaus. Die Band tritt gleich auf.\nB: Toll, wir sind rechtzeitig!",exampleSrc:"A: Please step in!\nB: Thanks! Where is the stage?\nA: Straight ahead. The band performs shortly.\nB: Great, we're on time!",funFact:"One root verb, many separable prefixes: eintreten (enter), auftreten (perform), austreten (exit). You already know auftreten from Lesson 5."},
{type:"drag_fill",s:"Mia singt laut, {1} alle mitsingen, {2} ihre Stimme zu verlieren.",blanks:{"1":"damit","2":"ohne"},pool:["damit","ohne","um","statt","weil"],hint:"First blank: Mia sings, others join in. Different doers. Second blank: Mia never loses her voice. An absent outcome.",sSrc:"Mia sings loudly so that everyone sings along, without losing her voice."},
{type:"mc",q:"Was bedeutet 'das Ballett'?",opts:["the ballet","to run (fast)","the talent","the listener, the receiver"],ans:"the ballet",hint:"French/Italian loanword. The classical dance form with tutus and pointe shoes."},
{type:"fb",s:"Die Parade ist {1} laut!",a:["wahnsinnig"],opts:["wahnsinnig","das Ballett","allerbest","der Schauspieler"],hint:"From Wahnsinn (madness/insanity). Used colloquially to mean 'incredibly' or 'crazily'.",sSrc:"The parade is insanely loud!"},
{type:"mc",q:"Was bedeutet 'allerbest'?",opts:["the gate, the goal","the very best of all","the talent","the listener (female)"],ans:"the very best of all",hint:"Aller- (of all) intensifier + a superlative. The absolute peak: nothing higher exists."},
{type:"fb",s:"Die Kinder {1} nach den Bonbons!",a:["springen"],opts:["der Schauspieler","springen","die H\\u00f6rerin","das Ballett"],hint:"A strong verb for leaping into the air. English cognate: 'spring'. Up and off the ground.",sSrc:"The children jump for the candy!"},
{type:"mc",q:"Was bedeutet 'rennen'?",opts:["to drive, to push, to do (sport)","to climb","to run (fast)","the listener, the receiver"],ans:"to run (fast)",hint:"Sounds like its English equivalent. A strong verb for sprinting at high speed on foot."},
{type:"fb",s:"Die Kinder {1} auf die Absperrung!",a:["klettern"],opts:["klettern","die Zuschauerin","das Ballett","treiben"],hint:"A verb for going upward using hands and feet, like on a ladder or tree.",sSrc:"The children climb on the barrier!"},
{type:"mc",q:"Was bedeutet 'treiben'?",opts:["the most beautiful of all","the listener, the receiver","the type, the guy","to drive, to push, to do (sport)"],ans:"to drive, to push, to do (sport)",hint:"Sounds like its English equivalent. Also used in the phrase 'treiben' meaning to do athletic activity."},
{type:"fb",s:"{1} Sie bitte ein!",a:["treten"],opts:["allersch\\u00f6nst","treten","springen","allerbest"],hint:"A strong verb meaning to step or kick. 'Ein-' prefix = stepping inside a room.",sSrc:"Please step in!"}
]},

// ─── Lesson 7: Kamelle und Konfetti ──────────────────────────
{id:"deu_r17l8",title:"Kamelle und Konfetti",icon:"\uD83C\uDF6C",xp:15,board:true,steps:[
{type:"intro",title:"Kamelle und Konfetti",desc:"Show what you can do. All four infinitive constructions tested. Literature and media vocabulary. No more warm-up rounds.",goals:["Prove mastery of all four infinitive constructions","Learn vocabulary for literature, media, and culture","Complete the toughest practice round of the carnival"]},
{type:"teach",trg:"der Maler",src:"the painter (male)",pos:"noun",gender:"m",note:"Masculine noun. From 'malen' (to paint) + '-er.'\nCovers both house painters and artists.",example:"A: Wer hat dieses Bild gemalt?\nB: Ein ber\u00fchmter Maler aus K\u00f6ln.\nA: Der Maler hat Talent.\nB: Maler und K\u00fcnstler, das ist oft dasselbe.",exampleSrc:"A: Who painted this picture?\nB: A famous painter from Cologne.\nA: The painter has talent.\nB: Painter and artist, that's often the same thing.",funFact:"Germany's most famous Maler: Albrecht D\u00fcrer, Caspar David Friedrich, Gerhard Richter. The word covers both house painters and Picassos."},
{type:"teach",trg:"die Malerin",src:"the painter (female)",pos:"noun",gender:"f",note:"Feminine noun. Maler + '-in.'\nK\u00e4the Kollwitz and Paula Modersohn-Becker are among Germany's greatest.",example:"A: Die Malerin stellt im Museum aus.\nB: Ihre Bilder sind wundersch\u00f6n.\nA: Eine talentierte Malerin.\nB: Ihre Werke h\u00e4ngen in Museen weltweit.",exampleSrc:"A: The painter exhibits in the museum.\nB: Her paintings are beautiful.\nA: A talented painter.\nB: Her works hang in museums worldwide.",funFact:"K\u00e4the Kollwitz and Paula Modersohn-Becker are among Germany's greatest Malerinnen. Their work hangs in museums worldwide."},
{type:"teach",trg:"der Schriftsteller",src:"the writer, the author (male)",pos:"noun",gender:"m",note:"Masculine noun. Schrift (writing) + stellen (to place) + '-er.'\nMore literary than 'Autor.'",example:"A: Wer ist dein Lieblingsschriftsteller?\nB: Thomas Mann. Ein gro\u00dfer Schriftsteller.\nA: Schriftsteller oder Autor?\nB: Schriftsteller klingt literarischer.",exampleSrc:"A: Who is your favorite writer?\nB: Thomas Mann. A great writer.\nA: Writer or author?\nB: Schriftsteller sounds more literary.",funFact:"Someone who 'places writing.' More literary than Autor. Goethe, Kafka, and Thomas Mann are Germany's iconic Schriftsteller."},
{type:"teach",trg:"die Schriftstellerin",src:"the writer, the author (female)",pos:"noun",gender:"f",note:"Feminine noun. Schriftsteller + '-in.'\nHerta M\u00fcller won the Nobel Prize in Literature.",example:"A: Die Schriftstellerin hat den Nobelpreis gewonnen.\nB: Wirklich? F\u00fcr welches Buch?\nA: F\u00fcr ihr Gesamtwerk.\nB: Eine gro\u00dfartige Schriftstellerin.",exampleSrc:"A: The writer won the Nobel Prize.\nB: Really? For which book?\nA: For her complete body of work.\nB: A magnificent writer.",funFact:"Herta M\u00fcller won the Nobel Prize. Christa Wolf defined East German literature. The -in makes any profession feminine."},
{type:"teach",trg:"der Autor",src:"the author (male)",pos:"noun",gender:"m",note:"Masculine noun. From Latin 'auctor.'\nBroader than Schriftsteller: books, articles, screenplays.",example:"A: Wer ist der Autor dieses Buches?\nB: Ein junger Autor aus Berlin.\nA: Jeder, der schreibt, ist ein Autor.\nB: Aber nicht jeder Autor ist ein Schriftsteller.",exampleSrc:"A: Who is the author of this book?\nB: A young author from Berlin.\nA: Everyone who writes is an author.\nB: But not every author is a Schriftsteller.",funFact:"Broader than Schriftsteller: an Autor writes books, articles, screenplays, blogs. Everyone who writes is an Autor. Not everyone is a Schriftsteller."},
{type:"match",pairs:[{trg:"die Malerin",src:"the painter (female)"},{trg:"der Schriftsteller",src:"the writer, the author (male)"},{trg:"die Schriftstellerin",src:"the writer, the author (female)"},{trg:"der Autor",src:"the author (male)"}]},
{type:"teach",trg:"die Autorin",src:"the author (female)",pos:"noun",gender:"f",note:"Feminine noun. Autor + '-in.'\nGermany's book market is the third largest in the world.",example:"A: Die Autorin stellt ihr neues Buch vor.\nB: Worüber schreibt sie?\nA: \u00dcber Karneval im Rheinland.\nB: Das wird bestimmt ein Bestseller!",exampleSrc:"A: The author presents her new book.\nB: What does she write about?\nA: About carnival in the Rhineland.\nB: That will surely be a bestseller!",funFact:"Germany's book market is the third largest in the world after the US and China. Autorinnen are well represented on bestseller lists."},
{type:"mc",q:"Wer malt die Masken f\u00fcr den Karneval?",opts:["ein Maler","ein Schriftsteller","ein Autor","ein Reporter"],ans:"ein Maler",hint:"Which profession involves painting? From 'malen' (to paint) plus the -er agent suffix."},
{type:"fb",s:"Die {1} stellt ihr neues Buch \u00fcber den K\u00f6lner Karneval vor.",a:["Autorin"],opts:["Autorin","Malerin","Schriftstellerin","Reporterin"],hint:"Which feminine noun is the broader term for any person who writes professionally?",sSrc:"The author presents her new book about Cologne carnival."}
]},
{id:"deu_r17l8b",title:"Kamelle und Konfetti (Teil 2)",icon:"\uD83C\uDF6C",xp:15,board:true,steps:[
{type:"intro",title:"Kamelle und Konfetti (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Roman",src:"the novel",pos:"noun",gender:"m",note:"Masculine noun. From French 'roman.'\nNot the nationality (that is 'R\u00f6mer').",example:"A: Liest du gerade einen Roman?\nB: Ja, einen deutschen Roman.\nA: Welchen?\nB: 'Die Blechtrommel' von G\u00fcnter Grass.",exampleSrc:"A: Are you reading a novel right now?\nB: Yes, a German novel.\nA: Which one?\nB: 'The Tin Drum' by G\u00fcnter Grass.",funFact:"Not the nationality (that would be 'R\u00f6mer'). The Bildungsroman (coming-of-age novel) is a German invention that influenced world literature."},
{type:"teach",trg:"das Gedicht",src:"the poem",pos:"noun",gender:"n",note:"Neuter noun because of the Ge- prefix. From 'dichten' (to compose).\nGoethe's Gedichte are memorized in every German school.",example:"A: Kennst du ein deutsches Gedicht?\nB: Ja! 'Der Erlk\u00f6nig' von Goethe.\nA: Beim Karneval gibt es auch Gedichte.\nB: Ja, humorvolle Reime bei den Sitzungen.",exampleSrc:"A: Do you know a German poem?\nB: Yes! 'The Erlking' by Goethe.\nA: At carnival there are poems too.\nB: Yes, humorous rhymes at the sessions.",funFact:"Neuter because of the Ge- prefix. Karneval has its own Gedicht tradition: humorous rhymes recited at Sitzungen."},
{type:"teach",trg:"die Erz\u00e4hlung",src:"the narrative, the short story",pos:"noun",gender:"f",note:"Feminine noun. From 'erz\u00e4hlen' (to tell/narrate).\nThe -ung suffix always makes feminine nouns.",example:"A: Ist das eine Erz\u00e4hlung oder ein Roman?\nB: Eine Erz\u00e4hlung. Zu kurz f\u00fcr einen Roman.\nA: Wor\u00fcber handelt die Erz\u00e4hlung?\nB: \u00dcber einen Fremden beim K\u00f6lner Karneval.",exampleSrc:"A: Is that a narrative or a novel?\nB: A narrative. Too short for a novel.\nA: What is the narrative about?\nB: About a stranger at Cologne carnival.",funFact:"The -ung suffix always makes feminine nouns. Kafka's 'Die Verwandlung' (The Metamorphosis) is Germany's most famous Erz\u00e4hlung."},
{type:"teach",trg:"die Literatur",src:"the literature",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'literatura.'\nGermany has produced 14 Nobel Prize winners in Literatur.",example:"A: Magst du deutsche Literatur?\nB: Ja, besonders die Klassiker.\nA: Literatur ist Kultur.\nB: Und Kultur ist beim Karneval \u00fcberall.",exampleSrc:"A: Do you like German literature?\nB: Yes, especially the classics.\nA: Literature is culture.\nB: And culture is everywhere at carnival.",funFact:"Germany has produced 14 Nobel Prize winners in Literatur. The Frankfurt Book Fair is the world's largest."},
{type:"teach",trg:"die Schrift",src:"the script, the writing, the typeface",pos:"noun",gender:"f",note:"Feminine noun. From 'schreiben' (to write).\nGutenberg's Druckerpresse made Schrift available to everyone.",example:"A: Was f\u00fcr eine Schrift ist das?\nB: Eine alte deutsche Schrift. Fraktur.\nA: Schwer zu lesen!\nB: Fr\u00fcher war das die normale Schrift.",exampleSrc:"A: What kind of script is that?\nB: An old German script. Fraktur.\nA: Hard to read!\nB: In the past that was the normal script.",funFact:"Gutenberg's printing press made Schrift available to everyone. The Lutheran Bible standardized German Schrift across dialects."},
{type:"teach",trg:"der Verlag",src:"the publishing house",pos:"noun",gender:"m",note:"Masculine noun. From 'verlegen' (to publish).\nGermany has over 2,000 Verlage.",example:"A: Welcher Verlag hat das Buch herausgegeben?\nB: Ein kleiner K\u00f6lner Verlag.\nA: Deutschland hat viele Verlage.\nB: \u00dcber 2.000! Lesen ist hier wichtig.",exampleSrc:"A: Which publisher released the book?\nB: A small Cologne publisher.\nA: Germany has many publishers.\nB: Over 2,000! Reading is important here.",funFact:"Germany has over 2,000 Verlage. The biggest: Bertelsmann, Springer, Suhrkamp. 'Im Verlag erscheinen' means 'to be published by.'"},
{type:"teach",trg:"das Medium",src:"the medium",pos:"noun",gender:"n",note:"Neuter noun. From Latin 'medium.' Plural: Medien.\n'Die Medien berichten \u00fcber Karneval.'",example:"A: Welches Medium nutzt du am meisten?\nB: Die Medien berichten \u00fcber Karneval.\nA: Fernsehen, Radio, Zeitung?\nB: Und Social Media! Alle Medien.",exampleSrc:"A: Which medium do you use the most?\nB: The media report on carnival.\nA: TV, radio, newspaper?\nB: And social media! All media.",funFact:"Plural: Medien. In German, Medien nearly always means news media. 'Die Medien berichten \u00fcber Karneval.'"},
{type:"teach",trg:"die Garantie",src:"the guarantee, the warranty",pos:"noun",gender:"f",note:"Feminine noun. From French 'garantie.'\n'Keine Garantie!' (No guarantee!).",example:"A: Gibt es eine Garantie f\u00fcr gutes Wetter?\nB: Keine Garantie! Aber Karneval feiert man bei jedem Wetter.\nA: Garantiert Spa\u00df?\nB: Das ist die einzige Garantie beim Karneval.",exampleSrc:"A: Is there a guarantee for good weather?\nB: No guarantee! But carnival is celebrated in any weather.\nA: Guaranteed fun?\nB: That's the only guarantee at carnival.",funFact:"At Karneval, it is the guarantee for a good time. In stores, Garantie means warranty. Same word, different context."},
{type:"teach",trg:"garantieren",src:"to guarantee",pos:"verb",gender:null,note:"From Garantie. Regular -ieren verb.\nAll -ieren verbs form past participle without ge-: garantiert.",example:"A: Kannst du mir Spa\u00df garantieren?\nB: Beim Karneval garantiert!\nA: Das hast du garantiert?\nB: Ich garantiere es. Hundert Prozent.",exampleSrc:"A: Can you guarantee me fun?\nB: At carnival, guaranteed!\nA: You guaranteed that?\nB: I guarantee it. One hundred percent.",funFact:"All -ieren verbs are regular and form their past participle without ge-: garantiert, not gegarantiert. A reliable pattern."},
{type:"teach",trg:"auff\u00fchren",src:"to perform, to stage",pos:"verb",gender:null,note:"Separable verb. Auf (up) + f\u00fchren (to lead).\nAlso 'sich auff\u00fchren' = to behave (usually badly).",example:"A: Welches St\u00fcck f\u00fchren sie auf?\nB: Eine Karnevalskomödie.\nA: Sie f\u00fchren es heute Abend auf.\nB: Und morgen f\u00fchren sie sich danach auf!",exampleSrc:"A: Which piece are they performing?\nB: A carnival comedy.\nA: They're staging it tonight.\nB: And tomorrow they'll behave badly afterward!",funFact:"'Ein St\u00fcck auff\u00fchren' = to perform a play. Also 'sich auff\u00fchren' = to behave (usually badly). 'F\u00fchr dich nicht so auf!' (Don't make a scene!)"},
{type:"teach",trg:"auffallen",src:"to stand out, to be noticeable",pos:"verb",gender:null,note:"Separable verb. Auf (up) + fallen (to fall).\n'Das f\u00e4llt auf!' (That stands out!).",example:"A: Dein Kost\u00fcm f\u00e4llt auf!\nB: Danke! Beim Karneval will man auffallen.\nA: Im Alltag f\u00e4llt man nicht gern auf.\nB: Aber heute: je mehr, desto besser!",exampleSrc:"A: Your costume stands out!\nB: Thanks! At carnival you want to stand out.\nA: In everyday life people don't like to stand out.\nB: But today: the more, the better!",funFact:"At Karneval, aufzufallen is the goal. In normal German life, it is often avoided. A complete cultural reversal."},
{type:"teach",trg:"verwenden",src:"to use, to employ",pos:"verb",gender:null,note:"Ver- + wenden (to turn). More formal than 'benutzen.'\nUsed for materials, methods, and resources.",example:"A: Welche Farben verwendest du?\nB: Rot, Gelb und Gr\u00fcn.\nA: Und welches Material?\nB: Ich verwende Pappe und Stoff.",exampleSrc:"A: Which colors do you use?\nB: Red, yellow, and green.\nA: And which material?\nB: I use cardboard and fabric.",funFact:"More formal than 'benutzen.' Used for materials, methods, and resources. 'Welche Farben verwendest du?'"},
{type:"teach",trg:"wetten",src:"to bet",pos:"verb",gender:null,note:"'Wetten, dass...?' (Wanna bet that...?).\nAlso Germany's biggest TV show for decades.",example:"A: Wetten, dass Verumius Spa\u00df hat?\nB: Darauf wette ich!\nA: Ich wette, er kommt n\u00e4chstes Jahr wieder.\nB: Darauf w\u00fcrde ich auch wetten.",exampleSrc:"A: Wanna bet that Verumius is having fun?\nB: I'd bet on that!\nA: I bet he'll come back next year.\nB: I'd bet on that too.",funFact:"'Wetten, dass...?' was also Germany's biggest TV show for decades. 'Ich wette, Verumius hat Spa\u00df.'"},
{type:"teach",trg:"irren",src:"to err, to be wrong",pos:"verb",gender:null,note:"'Sich irren' = to be mistaken.\n'Irren ist menschlich' (To err is human).",example:"A: Du irrst dich! Das ist kein Pirat.\nB: Oh, ich habe mich geirrt?\nA: Ja, das ist ein Wikinger!\nB: Irren ist menschlich.",exampleSrc:"A: You're wrong! That's not a pirate.\nB: Oh, I was mistaken?\nA: Yes, that's a Viking!\nB: To err is human.",funFact:"'Irren ist menschlich' (To err is human). 'Wer dachte, Deutsche haben keinen Humor, hat sich geirrt' (Whoever thought Germans have no humor was mistaken)."},
{type:"mc",q:"Wir fahren nach K\u00f6ln, ___ den Rosenmontagszug zu sehen.",opts:["um","damit","statt","ohne"],ans:"um",hint:"We travel with a PURPOSE: to see the parade. Same subject, purpose clause."},
{type:"mc",q:"Die Kinder fangen Bonbons, ___ hinzufallen.",opts:["um","ohne","damit","statt"],ans:"ohne",hint:"Catching candy is the main action; falling never happens. Which connector introduces the action that is absent?"},
{type:"fb",s:"Der S\u00e4nger singt laut, {1} das Publikum ihn h\u00f6rt.",a:["damit"],opts:["damit","um","ohne","statt"],hint:"The singer sings (subject 1) so that the audience (subject 2) hears. Different subjects.",sSrc:"The singer sings loudly so that the audience hears him."},
{type:"mc",q:"'Statt den Roman zu lesen, schaut er die Serie.' Was macht er?",opts:["Er liest den Roman und schaut die Serie","Er liest den Roman ohne zu schauen","Er schaut die Serie statt den Roman zu lesen","Er schaut, um zu lesen"],ans:"Er schaut die Serie statt den Roman zu lesen",hint:"Reading the novel is what he skips. Watching the show is the replacement. Which connector signals the skipped option?"},
{type:"drag_fill",s:"{1} nur zuzuh\u00f6ren, singt Verumius mit, {2} den Text zu kennen, {3} alle lachen.",blanks:{"1":"Statt","2":"ohne","3":"damit"},pool:["Statt","ohne","damit","um","weil","obwohl"],hint:"First blank: the alternative he skips. Second blank: a quality he lacks. Third blank: the intended result for others.",sSrc:"Instead of just listening, Verumius sings along without knowing the lyrics, so that everyone laughs."},
{type:"match",pairs:[{trg:"um...zu",src:"in order to"},{trg:"ohne...zu",src:"without doing"},{trg:"(an)statt...zu",src:"instead of doing"},{trg:"damit",src:"so that (different subject)"}]},
{type:"mc",q:"Ein Autor schreibt Romane. Ein Schriftsteller ist...",opts:["ein Sportler","ein Musiker","ein Maler","auch ein Autor"],ans:"auch ein Autor",hint:"Schriftsteller is the more literary term, but both write. One contains the other."},
{type:"fb",s:"Der Maler malt, {1} ber\u00fchmt zu werden.",a:["um"],opts:["um","ohne","statt","damit"],hint:"The purpose of painting: becoming famous. Same subject, purpose clause.",sSrc:"The painter paints in order to become famous."},
{type:"mc",q:"Mia erkl\u00e4rt die Tradition. Verumius soll alles verstehen. Mia will nicht gelangweilt klingen. Wie sagt man das in einem Satz?",opts:["Mia erkl\u00e4rt die Tradition, damit Verumius alles versteht, ohne gelangweilt zu klingen","Mia erkl\u00e4rt die Tradition, um alles zu verstehen, ohne gelangweilt zu klingen","Mia erkl\u00e4rt die Tradition, statt alles zu verstehen, um gelangweilt zu klingen","Mia erkl\u00e4rt die Tradition, ohne alles zu verstehen, damit gelangweilt klingt"],ans:"Mia erkl\u00e4rt die Tradition, damit Verumius alles versteht, ohne gelangweilt zu klingen",hint:"For the first sub-clause, check who does each action. For the second, the same speaker remains the subject throughout."},
{type:"mc",q:"Was bedeutet 'der Roman'?",opts:["the novel","to err, to be wrong","the author (female)","the literature"],ans:"the novel",hint:"French loanword from 'roman'. A long fictional narrative in prose, not poetry."},
{type:"fb",s:"Wie sagt man 'the poem' auf Deutsch? {1}",a:["das Gedicht"],opts:["garantieren","das Gedicht","die Erz\\u00e4hlung","auff\\u00fchren"],hint:"Related to 'dichten' (to compose verse). A literary work written in rhythmic lines.",sSrc:"How do you say 'the poem' in German?"},
{type:"mc",q:"Was bedeutet 'die Literatur'?",opts:["the script, the writing, the typeface","the literature","the painter (female)","the writer, the author (male)"],ans:"the literature",hint:"Latin cognate from 'littera' (letter). The body of written works, especially fiction and poetry."},
{type:"fb",s:"Wie sagt man 'the script, the writing, the typeface' auf Deutsch? {1}",a:["die Schrift"],opts:["die Malerin","der Maler","die Schrift","wetten"],hint:"From schreiben (to write). The visible form of writing: letters on a page or a font style.",sSrc:"How do you say 'the script, the writing, the typeface' in German?"},
{type:"mc",q:"Was bedeutet 'der Verlag'?",opts:["the painter (female)","the painter (male)","the publishing house","the script, the writing, the typeface"],ans:"the publishing house",hint:"From verlegen (to publish/relocate). The company that prints and distributes books."},
{type:"fb",s:"Wie sagt man 'the medium' auf Deutsch? {1}",a:["das Medium"],opts:["wetten","das Medium","die Erz\\u00e4hlung","die Schriftstellerin"],hint:"Latin cognate. A channel of communication (TV, radio, internet). Same spelling.",sSrc:"How do you say 'the medium' in German?"},
{type:"mc",q:"Was bedeutet 'die Garantie'?",opts:["the medium","the author (male)","to guarantee","the guarantee, the warranty"],ans:"the guarantee, the warranty",hint:"French cognate. A formal promise that something will work or be replaced."},
{type:"fb",s:"Kannst du mir Spa\\u00df {1}?",a:["garantieren"],opts:["die Schrift","auff\\u00fchren","die Erz\\u00e4hlung","garantieren"],hint:"The verb form of a French cognate for making a formal promise or assurance.",sSrc:"Can you guarantee me fun?"}
]},

// ─── Lesson 8: Konfetti im Haar ──────────────────────────────
{id:"deu_r17l9",title:"Konfetti im Haar",icon:"\u2728",xp:15,board:true,steps:[
{type:"intro",title:"Konfetti im Haar",desc:"ICE back to Berlin. Confetti in hair, wrinkled toga, crooked bee antennae. Verumius reflects on the craziest day of his life. Learn regional carnival names and pass the final test.",goals:["Wrap up the carnival experience","Learn regional carnival vocabulary and cultural contrasts","Pass the final test on all four infinitive constructions"]},
{type:"teach",trg:"der Fasching",src:"carnival (Bavarian/Austrian term)",pos:"noun",gender:"m",note:"Masculine noun. Southern German and Austrian word for carnival.\nFrom 'Fastenschank' (last drink before fasting).",example:"A: In M\u00fcnchen sagt man 'Fasching.'\nB: Und in K\u00f6ln 'Karneval.'\nA: Fasching, Karneval, Fasnacht.\nB: Drei Namen, eine Party!",exampleSrc:"A: In Munich they say 'Fasching.'\nB: And in Cologne 'Karneval.'\nA: Fasching, Karneval, Fasnacht.\nB: Three names, one party!",funFact:"In Munich they say Fasching, in Cologne Karneval, in Basel Fasnacht. Same party, three names. From 'Fastenschank' (last drink before fasting)."},
{type:"teach",trg:"die Fasnacht",src:"carnival (Swiss/Southwestern term)",pos:"noun",gender:"f",note:"Feminine noun. Swiss and Southwestern German.\nFrom 'Fasten' (fasting) + 'Nacht' (night).",example:"A: Basel feiert Fasnacht.\nB: Die Basler Fasnacht beginnt um vier Uhr morgens!\nA: Um vier? Das ist verr\u00fcckt.\nB: Jede Region hat ihre eigene Art.",exampleSrc:"A: Basel celebrates Fasnacht.\nB: Basel's Fasnacht starts at four in the morning!\nA: At four? That's crazy.\nB: Every region has its own way.",funFact:"Basel's Fasnacht starts at 4 AM in darkness. Each region owns its version. Fasten (fasting) + Nacht (night): the night before fasting begins."},
{type:"teach",trg:"der Friseur",src:"the hairdresser (male)",pos:"noun",gender:"m",note:"Masculine noun. From French 'friseur.'\nAfter Karneval, Friseure have their busiest week.",example:"A: Ich muss zum Friseur nach dem Karneval.\nB: Warum?\nA: Gl\u00fcckshaarspray und Konfetti.\nB: Nach dem Karneval ist immer Hochsaison beim Friseur.",exampleSrc:"A: I need to go to the hairdresser after carnival.\nB: Why?\nA: Glitter hairspray and confetti.\nB: After carnival is always peak season at the hairdresser.",funFact:"After Karneval, Friseure have their busiest week: washing out hair dye, glitter, and face paint. Germany has over 80,000 Friseur salons."},
{type:"teach",trg:"die Frisur",src:"the hairstyle",pos:"noun",gender:"f",note:"Feminine noun. From French 'frisure.'\n'Sch\u00f6ne Frisur!' is a genuine compliment.",example:"A: Sch\u00f6ne Frisur! Ist das f\u00fcr den Karneval?\nB: Ja, eine Karnevalsfrisur mit Gl\u00fccksstr\u00e4hnen.\nA: Kreative Frisuren geh\u00f6ren zum Karneval.\nB: Nach dem Fest brauche ich eine neue Frisur.",exampleSrc:"A: Nice hairstyle! Is that for carnival?\nB: Yes, a carnival hairstyle with glitter streaks.\nA: Creative hairstyles are part of carnival.\nB: After the party I'll need a new hairstyle.",funFact:"Karneval Frisuren range from elaborate wigs to spray-painted mohawks. 'Sch\u00f6ne Frisur!' is a genuine compliment in German."},
{type:"teach",trg:"der Coiffeur",src:"the hairdresser (Swiss German)",pos:"noun",gender:"m",note:"Masculine noun. Swiss German for Friseur.\nDirectly from French.",example:"A: In der Schweiz sagt man 'Coiffeur.'\nB: Und in Deutschland 'Friseur.'\nA: Beide aus dem Franz\u00f6sischen.\nB: Die Schweiz liebt franz\u00f6sische W\u00f6rter.",exampleSrc:"A: In Switzerland they say 'Coiffeur.'\nB: And in Germany 'Friseur.'\nA: Both from French.\nB: Switzerland loves French words.",funFact:"In Switzerland, you go to the Coiffeur, not the Friseur. Same job, French word, Swiss identity."},
{type:"match",pairs:[{trg:"die Fasnacht",src:"carnival (Swiss/Southwestern term)"},{trg:"der Friseur",src:"the hairdresser (male)"},{trg:"die Frisur",src:"the hairstyle"},{trg:"der Coiffeur",src:"the hairdresser (Swiss German)"}]},
{type:"teach",trg:"die Coiffeuse",src:"the hairdresser (female, Swiss)",pos:"noun",gender:"f",note:"Feminine noun. French feminine form.\nOne of few profession pairs using a French feminine instead of -in.",example:"A: Die Coiffeuse schneidet mir die Haare.\nB: Nicht 'Friseurin'?\nA: In der Schweiz: Coiffeuse.\nB: Jedes Land hat seine eigenen W\u00f6rter.",exampleSrc:"A: The hairdresser cuts my hair.\nB: Not 'Friseurin'?\nA: In Switzerland: Coiffeuse.\nB: Every country has its own words.",funFact:"One of the few profession pairs that uses a French feminine form instead of the German -in suffix. Swiss German identity in one word."},
{type:"teach",trg:"der Bart",src:"the beard",pos:"noun",gender:"m",note:"Masculine noun. Same root as English 'beard.'\n'Sich einen Bart wachsen lassen' = to grow a beard.",example:"A: Ist das ein echter Bart?\nB: Nein, ein Karnevalsbart!\nA: Falsche B\u00e4rte sind das beliebteste Accessoire.\nB: Nach den H\u00fcten.",exampleSrc:"A: Is that a real beard?\nB: No, a carnival beard!\nA: Fake beards are the most popular accessory.\nB: After hats.",funFact:"Fake B\u00e4rte (beards) are the most popular Karneval accessory after hats. 'Sich einen Bart wachsen lassen' = to grow a beard."},
{type:"teach",trg:"die Socke",src:"the sock",pos:"noun",gender:"f",note:"Feminine noun. From Latin 'soccus' (light shoe).\n'Von den Socken sein' = to be blown away.",example:"A: Bunte Socken zum Kost\u00fcm?\nB: Nat\u00fcrlich! Alles muss bunt sein.\nA: Ich bin von den Socken!\nB: Das hei\u00dft, du bist \u00fcberrascht.",exampleSrc:"A: Colorful socks with the costume?\nB: Of course! Everything has to be colorful.\nA: I'm knocked off my socks!\nB: That means you're surprised.",funFact:"'Von den Socken sein' means to be blown away, literally 'knocked off your socks.' Karneval will leave you von den Socken."},
{type:"teach",trg:"der Strumpf",src:"the stocking",pos:"noun",gender:"m",note:"Masculine noun. Strumpfhosen (tights) are part of many Karneval costumes.\n'Pippi Langstrumpf' is named after her long stockings.",example:"A: Wer ist Pippi Langstrumpf?\nB: Ein schwedisches M\u00e4dchen mit langen Str\u00fcmpfen.\nA: Langstrumpf bedeutet 'long stocking'?\nB: Genau! Das st\u00e4rkste M\u00e4dchen der Welt.",exampleSrc:"A: Who is Pippi Longstocking?\nB: A Swedish girl with long stockings.\nA: Langstrumpf means 'long stocking'?\nB: Exactly! The strongest girl in the world.",funFact:"'Pippi Langstrumpf' (Pippi Longstocking) is named after her long stockings. Germans love this character. Strumpfhosen are part of many costumes."},
{type:"teach",trg:"der K\u00f6nig",src:"the king",pos:"noun",gender:"m",note:"Masculine noun. From Old High German 'kuning.'\n'Der Kunde ist K\u00f6nig' (The customer is king).",example:"A: Wer ist der K\u00f6nig des Karnevals?\nB: Es gibt einen Prinzen, keinen K\u00f6nig.\nA: Warum keinen K\u00f6nig?\nB: Karneval parodiert die Macht. Prinz reicht.",exampleSrc:"A: Who is the king of carnival?\nB: There's a prince, not a king.\nA: Why no king?\nB: Carnival parodies power. A prince is enough.",funFact:"Carnival has a Prinz (prince), not a K\u00f6nig. K\u00f6nig appears everywhere in German culture: 'Der Kunde ist K\u00f6nig' (The customer is king)."},
{type:"match",pairs:[{trg:"der Bart",src:"the beard"},{trg:"die Socke",src:"the sock"},{trg:"der Strumpf",src:"the stocking"},{trg:"der K\u00f6nig",src:"the king"}]},
{type:"mc",q:"Was ist der Unterschied zwischen 'Fasching' und 'Karneval'?",opts:["Verschiedene Regionen, gleiche Tradition","Karneval findet nur in Berlin statt","Die beiden Feste haben gar nichts gemeinsam","Fasching ist immer nur ein Essen"],ans:"Verschiedene Regionen, gleiche Tradition",hint:"Both refer to the same celebration but are used in different parts of Germany."},
{type:"fb",s:"Ich gehe zum {1}, um mir die Haare schneiden zu lassen.",a:["Friseur"],opts:["Friseur","König","Bart","Fasching"],hint:"A person who cuts hair professionally.",sSrc:"I'm going to the hairdresser to get my hair cut."},
{type:"match",pairs:[{trg:"der Fasching",src:"carnival (southern)"},{trg:"der Friseur",src:"hairdresser"},{trg:"der Bart",src:"beard"},{trg:"die Socke",src:"sock"},{trg:"der König",src:"king"}]},
{type:"mc",q:"In der Schweiz sagt man nicht 'Friseur.' Welches Wort benutzt man?",opts:["Strumpf","Coiffeur","Fasching","König"],ans:"Coiffeur",hint:"A French-origin word used in Switzerland and parts of Austria for hairdresser."},
{type:"fb",s:"Die Schüler {1} ein Theaterstück auf der Bühne auf.",a:"führen",opts:["führen","fallen","wenden","stellen"],hint:"The separable verb 'aufführen' means to perform or stage a play. What goes before 'auf'?",sSrc:"The students perform a play on the stage."},
{type:"mc",q:"Er fällt sofort auf, weil er so groß ist. Was bedeutet 'auffallen'?",opts:["to perform","to use","to stand out","to fall down"],ans:"to stand out",hint:"A separable verb meaning to be noticeable or to attract attention."},
{type:"fb",s:"Welches Material {1} Sie für das Kostüm?",a:"verwenden",opts:["verwenden","auffallen","aufführen","verkleiden"],hint:"A verb meaning to use or employ materials for a specific purpose.",sSrc:"Which material do you use for the costume?"}
]},

// ─── L9: Adjektive und Freizeitverben ───
{id:"deu_r17l10",title:"Adjektive und Freizeitverben",icon:"🎨",xp:10,board:true,steps:[
{type:"intro",title:"Adjektive und Freizeitverben",desc:"Descriptive adjectives, time adverbs, and leisure verbs to talk about what you do for fun. Plus German prefix patterns: aller-, doppel-, wieder-, zusammen-.",goals:["Use descriptive adjectives: färbig, stilistisch, doppelt","Master time adverbs: kürzlich, neulich, irgendwann","Learn leisure verbs: faulenzen, zelten, tauchen"]},
{type:"teach",trg:"f\u00e4rbig",src:"colored, colorful",pos:"adj",gender:null,note:"From 'Farbe' (color) + '-ig.' Variant of 'farbig.'\nMore southern German. Both forms are correct.",example:"A: Die Stra\u00dfen sind so f\u00e4rbig!\nB: Man sagt auch 'farbig.'\nA: Beides ist richtig?\nB: Ja, Deutsch hat oft zwei Formen.",exampleSrc:"A: The streets are so colorful!\nB: You can also say 'farbig.'\nA: Both are correct?\nB: Yes, German often has two forms.",funFact:"F\u00e4rbig is more southern, farbig more northern. Both mean 'colorful.' Having two forms for the same word is typically German."},
{type:"teach",trg:"farbig",src:"colored, colorful",pos:"adj",gender:null,note:"From 'Farbe' + '-ig.' Variant of 'f\u00e4rbig.'\nMore northern German. Both are correct.",example:"A: Karneval ist das farbigste Fest.\nB: So viele Farben auf einmal.\nA: Farbig und laut und verr\u00fcckt.\nB: Genau so soll es sein.",exampleSrc:"A: Carnival is the most colorful festival.\nB: So many colors at once.\nA: Colorful and loud and crazy.\nB: That's exactly how it should be.",funFact:"The difference is regional: f\u00e4rbig is more southern, farbig more northern. Both mean 'colorful.' Karneval is the most farbig event in Germany."},
{type:"teach",trg:"stilistisch",src:"stylistic",pos:"adj",gender:null,note:"From 'Stil' (style) + '-istisch.'\nUsed for art, writing, and fashion criticism.",example:"A: Das Kost\u00fcm ist stilistisch perfekt.\nB: Jedes Detail stimmt.\nA: Stilistisch durchdacht.\nB: Kunst am K\u00f6rper.",exampleSrc:"A: The costume is stylistically perfect.\nB: Every detail is right.\nA: Stylistically thought through.\nB: Art on the body.",funFact:"Used for art, writing, and fashion criticism. The best Karneval costumes are stilistisch durchdacht (stylistically thought through)."},
{type:"teach",trg:"k\u00fcrzlich",src:"recently",pos:"adv",gender:null,note:"From 'kurz' (short) + '-lich.'\nSomething that happened a short time ago.",example:"A: K\u00fcrzlich war ich in K\u00f6ln.\nB: Beim Karneval?\nA: Ja, k\u00fcrzlich erst. Letzte Woche.\nB: Und? Wie war es?",exampleSrc:"A: Recently I was in Cologne.\nB: At carnival?\nA: Yes, just recently. Last week.\nB: And? How was it?",funFact:"From 'kurz' (short) + '-lich.' Something that happened a short time ago. An adverb of recent time."},
{type:"teach",trg:"doppelt",src:"double",pos:"adj",gender:null,note:"From 'doppel-.' 'Doppelt gemoppelt' = redundant.\nSome people wear doppelte Kost\u00fcme: two characters in one.",example:"A: Doppelt so viel Konfetti wie letztes Jahr!\nB: Doppelt so laut, doppelt so bunt.\nA: Alles war doppelt so gut.\nB: Doppelt gemoppelt? Nein, doppelt genie\u00dfen!",exampleSrc:"A: Double the confetti compared to last year!\nB: Twice as loud, twice as colorful.\nA: Everything was twice as good.\nB: Redundant? No, double the enjoyment!",funFact:"'Doppelt gemoppelt' (doubly done, redundant) is a fun German saying. Some people wear doppelte costumes: two characters in one outfit."},
{type:"match",pairs:[{trg:"farbig",src:"colored, colorful"},{trg:"stilistisch",src:"stylistic"},{trg:"k\u00fcrzlich",src:"recently"},{trg:"doppelt",src:"double"}]},
{type:"teach",trg:"neulich",src:"recently, the other day",pos:"adv",gender:null,note:"From 'neu' (new) + '-lich.' Similar to k\u00fcrzlich but more conversational.\nWarm, storytelling register.",example:"A: Neulich habe ich Mia getroffen.\nB: Ach ja? Wo denn?\nA: Beim Karneval in K\u00f6ln.\nB: Neulich war ich auch dort!",exampleSrc:"A: The other day I met Mia.\nB: Really? Where?\nA: At carnival in Cologne.\nB: The other day I was there too!",funFact:"Similar to k\u00fcrzlich but more conversational and warm. 'Neulich habe ich Mia getroffen' has a storytelling quality."},
{type:"mc",q:"Die Stra\u00dfen beim Karneval sind voller Farben. Welches Adjektiv beschreibt sie am besten?",opts:["farbig","neulich","stilistisch","doppelt"],ans:"farbig",hint:"Which adjective means 'colorful,' directly derived from the noun Farbe (color)?"},
{type:"fb",s:"Alles war {1} so gut wie letztes Jahr.",a:["doppelt"],opts:["doppelt","k\u00fcrzlich","stilistisch","neulich"],hint:"Which word means 'double' or 'twice as much'?",sSrc:"Everything was twice as good as last year."},
{type:"teach",trg:"irgendwann",src:"someday, at some point",pos:"adv",gender:null,note:"Irgend- (some-) + wann (when).\nIrgend- makes question words indefinite: irgendwo, irgendwer.",example:"A: Kommst du irgendwann wieder nach K\u00f6ln?\nB: Irgendwann bestimmt!\nA: Vielleicht n\u00e4chstes Jahr?\nB: Irgendwann, versprochen.",exampleSrc:"A: Will you come back to Cologne someday?\nB: Someday for sure!\nA: Maybe next year?\nB: Someday, I promise.",funFact:"Irgend- is a prefix that makes question words indefinite: irgendwann (sometime), irgendwo (somewhere), irgendwer (someone)."},
{type:"teach",trg:"sowieso",src:"anyway, regardless",pos:"part",gender:null,note:"A very common filler in spoken German.\nThree syllables: so-wie-so. Shrugs off objections.",example:"A: Sollen wir ein Taxi nehmen?\nB: Das wollte ich sowieso vorschlagen.\nA: Ich bin sowieso m\u00fcde.\nB: Nach dem Karneval ist man sowieso m\u00fcde.",exampleSrc:"A: Should we take a taxi?\nB: I was going to suggest that anyway.\nA: I'm tired anyway.\nB: After carnival you're tired anyway.",funFact:"A very common filler in spoken German. Three syllables: so-wie-so. Shrugs off objections elegantly."},
{type:"teach",trg:"rasieren",src:"to shave",pos:"verb",gender:null,note:"'Sich rasieren' (to shave oneself). From French 'raser.'\nAfter Karneval, men discover glitter under fake beards.",example:"A: Ich muss mich rasieren.\nB: Den Karnevalsbart abrasieren?\nA: Ja, und darunter ist Glitzer.\nB: Glitzer geht nie ganz weg.",exampleSrc:"A: I need to shave.\nB: Shave off the carnival beard?\nA: Yes, and underneath there's glitter.\nB: Glitter never fully goes away.",funFact:"After Karneval, many men rasieren off their fake beards and discover glitter underneath that lasts for weeks."},
{type:"teach",trg:"vergn\u00fcgen",src:"to enjoy, to amuse (reflexive)",pos:"verb",gender:null,note:"'Sich vergn\u00fcgen' (to enjoy oneself). The verb form of Vergn\u00fcgen.\nPast participle 'vergn\u00fcgt' doubles as an adjective.",example:"A: Habt ihr euch vergn\u00fcgt?\nB: Ja, wir haben uns k\u00f6stlich vergn\u00fcgt!\nA: Man kann sich immer vergn\u00fcgen.\nB: Beim Karneval besonders.",exampleSrc:"A: Did you enjoy yourselves?\nB: Yes, we had a wonderful time!\nA: You can always enjoy yourself.\nB: At carnival especially.",funFact:"Reflexive: 'sich vergn\u00fcgen.' The past participle 'vergn\u00fcgt' doubles as an adjective meaning cheerful or amused."},
{type:"teach",trg:"faulenzen",src:"to laze around",pos:"verb",gender:null,note:"From 'faul' (lazy) + '-enzen.'\nA guilt-free verb. Everyone deserves to faulenzen sometimes.",example:"A: Was machst du morgen?\nB: Faulenzen. Den ganzen Tag.\nA: Nach dem Karneval verdient man das.\nB: Faulenzen ist die beste Medizin.",exampleSrc:"A: What are you doing tomorrow?\nB: Lazing around. All day.\nA: After carnival you deserve that.\nB: Lazing around is the best medicine.",funFact:"From 'faul' (lazy) + '-enzen.' A guilt-free verb. 'Nach dem Karneval faulenze ich den ganzen Tag.'"},
{type:"fb",s:"Das Kost\u00fcm ist {1} perfekt. Jedes Detail stimmt.",a:["stilistisch"],opts:["stilistisch","doppelt","f\u00e4rbig","neulich"],hint:"Which adjective describes something from a style or design perspective?",sSrc:"The costume is stylistically perfect. Every detail is right."},
{type:"mc",q:"Verumius war letzte Woche beim Karneval. Welches Wort passt?",opts:["irgendwann (nein)","sowieso","k\u00fcrzlich","doppelt"],ans:"k\u00fcrzlich",hint:"Which adverb means 'recently' or 'a short time ago'? From 'kurz' (short)."}
]},
{id:"deu_r17l10b",title:"Adjektive und Freizeitverben (Teil 2)",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Adjektive und Freizeitverben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"tauchen",src:"to dive",pos:"verb",gender:null,note:"'Ins Wasser tauchen' (to dive into water).\n'Auftauchen' = to surface/appear.",example:"A: Beim Karneval taucht man in die Menge ein.\nB: Und nach dem Karneval taucht man wieder auf.\nA: Eintauchen und auftauchen.\nB: Wie ein Taucher im Meer der Freude.",exampleSrc:"A: At carnival you dive into the crowd.\nB: And after carnival you surface again.\nA: Diving in and surfacing.\nB: Like a diver in a sea of joy.",funFact:"Also 'auftauchen' (to surface/appear). At Karneval, man taucht ein in die Menge (one dives into the crowd). Both literal and figurative."},
{type:"teach",trg:"zelten",src:"to camp",pos:"verb",gender:null,note:"From 'Zelt' (tent). Regular verb.\nDie-hard fans zelten overnight along the parade route.",example:"A: Manche Leute zelten am Stra\u00dfenrand.\nB: \u00dcber Nacht? F\u00fcr den besten Platz?\nA: Ja! Zelten f\u00fcr den Rosenmontagszug.\nB: Das ist wahrer Karnevalsgeist.",exampleSrc:"A: Some people camp on the roadside.\nB: Overnight? For the best spot?\nA: Yes! Camping for the Rose Monday parade.\nB: That's true carnival spirit.",funFact:"Some die-hard carnival fans zelten along the parade route overnight to get the best spots for the Rosenmontagszug."},
{type:"teach",trg:"zuschauen",src:"to watch",pos:"verb",gender:null,note:"Separable verb. Zu (at) + schauen (to look).\nSynonym of zugucken. 'Ich schaue gerne zu.'",example:"A: Ich schaue gerne zu.\nB: Beim Karneval kann man nicht nur zuschauen.\nA: Man muss mitmachen?\nB: Genau! Zuschauen reicht nicht.",exampleSrc:"A: I like to watch.\nB: At carnival you can't just watch.\nA: You have to join in?\nB: Exactly! Watching isn't enough.",funFact:"Synonym of zugucken. Separable: 'Ich schaue gerne zu.' The zu- prefix means 'at/toward.'"},
{type:"teach",trg:"vergn\u00fcgt",src:"amused, cheerful",pos:"adj",gender:null,note:"Past participle of vergn\u00fcgen used as adjective.\n'Sie sieht vergn\u00fcgt aus' (She looks cheerful).",example:"A: Du siehst vergn\u00fcgt aus.\nB: Bin ich auch! Karneval war toll.\nA: Verumius f\u00fchlt sich vergn\u00fcgt.\nB: Vergn\u00fcgt und m\u00fcde. Die beste Kombination.",exampleSrc:"A: You look cheerful.\nB: I am! Carnival was great.\nA: Verumius feels amused.\nB: Cheerful and tired. The best combination.",funFact:"Past participle of vergn\u00fcgen used as adjective. Vergn\u00fcgt is how Verumius feels: amused, cheerful, deeply satisfied."},
{type:"teach",trg:"aller-",src:"(prefix) of all, the very (superlative amplifier)",pos:"part",gender:null,note:"Prefix that amplifies superlatives to maximum.\naller- + best = allerbest (the very best of all).",example:"A: Das war der allerbeste Tag!\nB: Und das allersch\u00f6nste Erlebnis.\nA: Aller- macht alles noch intensiver.\nB: Das allerwichtigste Wort beim Karneval: Alaaf!",exampleSrc:"A: That was the very best day!\nB: And the most beautiful experience of all.\nA: Aller- makes everything even more intense.\nB: The most important word at carnival: Alaaf!",funFact:"Aller- cranks any superlative to maximum: allerbest, allersch\u00f6nst, allerwichtigst. You can attach it to any superlative in German."},
{type:"mc",q:"Verumius hat sich den ganzen Tag nicht bewegt. Was hat er gemacht?",opts:["Er hat gefaulenzt","Er hat getaucht","Er hat zugeschaut (nein)","Er hat gezeltet"],ans:"Er hat gefaulenzt",hint:"Which verb means to laze around, doing nothing all day? Comes from 'faul' (lazy)."},
{type:"fb",s:"Verumius will {1} nach K\u00f6ln zur\u00fcckkommen.",a:["irgendwann"],opts:["irgendwann","neulich","k\u00fcrzlich","sowieso"],hint:"Which adverb means 'someday' or 'at some point in the future'?",sSrc:"Verumius wants to come back to Cologne someday."},
{type:"teach",trg:"doppel-",src:"(prefix) double",pos:"part",gender:null,note:"Prefix meaning 'double.' Builds compounds freely.\ndoppel- + Punkt = Doppelpunkt (colon).",example:"A: Ein Doppelzimmer, bitte.\nB: Doppel- bedeutet immer 'zwei.'\nA: Doppelt gemoppelt!\nB: Das hei\u00dft: unn\u00f6tig wiederholt.",exampleSrc:"A: A double room, please.\nB: Doppel- always means 'two.'\nA: Doubly done!\nB: That means: unnecessarily repeated.",funFact:"Builds compounds freely: Doppelzimmer (double room), Doppelpunkt (colon), Doppelg\u00e4nger (a word English borrowed directly from German)."},
{type:"teach",trg:"wieder-",src:"(prefix) again, re-",pos:"part",gender:null,note:"Prefix meaning 'again.' Separable in most verbs.\nwiedersehen = to see again, wiederholen = to repeat.",example:"A: Wir sehen uns wieder!\nB: Wiedersehen beim n\u00e4chsten Karneval?\nA: Auf Wiedersehen!\nB: Bis wir uns wiedersehen!",exampleSrc:"A: We'll see each other again!\nB: See you again at the next carnival?\nA: Goodbye! (lit: until seeing again)\nB: Until we see each other again!",funFact:"'Auf Wiedersehen' (goodbye) literally means 'until seeing again.' Wieder- as a prefix adds 'again' to any verb: wiederkommen, wiederfinden, wiederholen."},
{type:"teach",trg:"zusammen-",src:"(prefix) together",pos:"part",gender:null,note:"Prefix meaning 'together.' Very productive in German.\nzusammenarbeiten = to work together, zusammenleben = to live together.",example:"A: Zusammen feiern ist sch\u00f6ner.\nB: Zusammen singen, zusammen tanzen.\nA: Zusammen ist alles besser.\nB: Das ist die Botschaft des Karnevals.",exampleSrc:"A: Celebrating together is nicer.\nB: Singing together, dancing together.\nA: Together everything is better.\nB: That's the message of carnival.",funFact:"Very productive: zusammenarbeiten (work together), zusammenleben (live together), zusammenhalten (hold together). Karneval is all about zusammen."},
{type:"tip",title:"Three Carnivals, One Country",text:"Karneval (Rhineland: K\u00f6ln, D\u00fcsseldorf, Mainz)\nFasching (Bavaria, Austria)\nFasnacht (Switzerland, southwestern Germany)\n\nSame celebration, different names, different traditions.\nCologne's Karneval is the biggest: over 1 million people on Rosenmontag.\nBasel's Fasnacht starts at 4 AM in darkness.\nMunich's Fasching is family-friendly.\nThe Rhineland invented organized carnival chaos.\nEvery region insists its version is the best.",deepDive:{title:"Karnevalsgesellschaften: The Organizers Behind the Chaos",text:"Karneval is not spontaneous. Behind the chaos are 'Karnevalsgesellschaften' (carnival societies): clubs that plan carnival all year round.\n\nThey organize:\n- Sitzungen (formal show evenings)\n- Den Rosenmontagszug (the Rose Monday parade)\n- Prinzenpaar elections (the carnival prince and princess)\n- Karnevalslieder (carnival songs)\n\nThe oldest societies are over 200 years old. Becoming a member is an honor. The hierarchy is strict, but the fun is worth it."}},
{type:"mc",q:"In M\u00fcnchen sagt man nicht 'Karneval.' Wie hei\u00dft es dort?",opts:["Helau","Fasching","Fasnacht (nein)","Alaaf"],ans:"Fasching",hint:"The Bavarian and Austrian word for the same celebration."},
{type:"drag_fill",s:"Verumius reist nach K\u00f6ln, {1} Karneval zu erleben, {2} die Regeln zu kennen, und Mia erkl\u00e4rt alles, {3} er sich nicht irrt.",blanks:{"1":"um","2":"ohne","3":"damit"},pool:["um","ohne","damit","statt","weil","obwohl"],hint:"Purpose (in order to), absence (without knowing), different subject (so that he doesn't make mistakes).",sSrc:"Verumius travels to Cologne in order to experience carnival, without knowing the rules, and Mia explains everything so that he doesn't make mistakes."},
{type:"match",pairs:[{trg:"Vergn\u00fcgen",src:"pleasure"},{trg:"Unterhaltung",src:"entertainment"},{trg:"Neuigkeit",src:"news"},{trg:"Tradition",src:"tradition"}]},
{type:"mc",q:"Was bedeutet 'tauchen'?",opts:["(prefix) of all, the very (superlative amplifier)","to watch","to dive","colored, colorful"],ans:"to dive",hint:"Going under water. 'Taucherboot' = a vessel that submerges. Used for swimming deep."},
{type:"fb",s:"Manche Leute {1} am Stra\\u00dfenrand.",a:["zelten"],opts:["zelten","f\\u00e4rbig","faulenzen","farbig"],hint:"From Zelt (tent). A verb meaning to sleep outdoors in a temporary shelter.",sSrc:"Some people camp on the roadside."},
{type:"mc",q:"Was bedeutet 'zuschauen'?",opts:["to shave","colored, colorful","stylistic","to watch"],ans:"to watch",hint:"Zu- (toward) + schauen (to look). To sit and observe something happening, like a spectator."},
{type:"fb",s:"{1} macht alles noch intensiver.",a:["aller-"],opts:["aller-","stilistisch","f\\u00e4rbig","farbig"],hint:"A superlative intensifier meaning 'of all things.' Boosts any superlative to its maximum.",sSrc:"Aller- makes everything even more intense."},
{type:"mc",q:"Was bedeutet 'doppel-'?",opts:["(prefix) double","colored, colorful","double","(prefix) again, re-"],ans:"(prefix) double",hint:"Sounds like its English equivalent. Indicates two of something or twice as much."},
{type:"fb",s:"Wie sagt man '(prefix) again, re-' auf Deutsch? {1}",a:["wieder-"],opts:["sowieso","rasieren","wieder-","f\\u00e4rbig"],hint:"A separable prefix meaning 'once more'. Like English 're-' but more transparent.",sSrc:"How do you say '(prefix) again, re-' in German?"},
{type:"mc",q:"Was bedeutet 'zusammen-'?",opts:["stylistic","(prefix) together","colored, colorful","colored, colorful"],ans:"(prefix) together",hint:"A separable word meaning 'jointly' or 'as a group'. Opposite of 'auseinander-'."}
,{type:"match",pairs:[{trg:"gr\u00fc\u00dfen",src:"to greet"},{trg:"gucken",src:"to look, to peek"},{trg:"diesmal",src:"this time"},{trg:"die S\u00e4ngerin",src:"the singer (female)"},{trg:"musikalisch",src:"musical"},{trg:"popul\u00e4r",src:"popular"}]},{type:"match",pairs:[{trg:"schick",src:"stylish, chic"},{trg:"am\u00fcsieren",src:"to amuse, to have fun"},{trg:"l\u00e4cheln",src:"to smile"},{trg:"die Szene",src:"the scene"},{trg:"der Trainer",src:"the coach (male)"},{trg:"die Trainerin",src:"the coach (female)"}]},{type:"match",pairs:[{trg:"der Spielplatz",src:"the playground"},{trg:"das Stadion",src:"the stadium"},{trg:"der Rekord",src:"the record (competitive)"},{trg:"der Sieg",src:"the victory"},{trg:"der Sieger",src:"the winner, the victor"},{trg:"die Siegerin",src:"the winner (female)"}]},{type:"match",pairs:[{trg:"siegen",src:"to win, to be victorious"},{trg:"starten",src:"to start, to launch"},{trg:"die Reporterin",src:"the reporter (female)"},{trg:"die Journalistin",src:"the journalist (female)"},{trg:"sorgen",src:"to take care of, to ensure"},{trg:"die Zuh\u00f6rerin",src:"the listener (female)"}]},{type:"match",pairs:[{trg:"die H\u00f6rerin",src:"the listener (female)"},{trg:"das Ballett",src:"the ballet"},{trg:"rennen",src:"to run (fast)"},{trg:"treiben",src:"to drive, to push, to do (sport)"},{trg:"die Erz\u00e4hlung",src:"the narrative, the short story"},{trg:"der Verlag",src:"the publishing house"}]},{type:"match",pairs:[{trg:"auff\u00fchren",src:"to perform, to stage"},{trg:"auffallen",src:"to stand out, to be noticeable"},{trg:"wetten",src:"to bet"},{trg:"irren",src:"to err, to be wrong"},{trg:"die Coiffeuse",src:"the hairdresser (female, Swiss)"},{trg:"f\u00e4rbig",src:"colored, colorful"}]},{type:"match",pairs:[{trg:"rasieren",src:"to shave"},{trg:"faulenzen",src:"to laze around"},{trg:"tauchen",src:"to dive"},{trg:"zuschauen",src:"to watch"},{trg:"vergn\u00fcgt",src:"amused, cheerful"},{trg:"doppel-",src:"(prefix) double"}]},{type:"match",pairs:[{trg:"zusammen-",src:"(prefix) together"}]}]}

]};

export default UNIT_17;
